package com.UIN.Tool;

import android.app.ActivityManager;
import android.app.AlertDialog;
import android.content.Intent;
import android.net.Uri;
import android.os.Build;
import android.os.Bundle;
import android.os.Environment;
import android.provider.Settings;
import android.widget.FrameLayout;
import android.widget.Toast;

import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.Fragment;
import androidx.fragment.app.FragmentManager;
import androidx.fragment.app.FragmentTransaction;

import com.UIN.Tool.ui.dev.DevFragment;
import com.UIN.Tool.ui.manage.ManageFragment;
import com.UIN.Tool.ui.tools.ToolsFragment;
import com.UIN.Tool.utils.CrashHandler;
import com.UIN.Tool.utils.LogUtils;
import com.UIN.Tool.utils.PreferencesUtils;
import com.UIN.Tool.utils.UIConfig;
import com.google.android.material.bottomnavigation.BottomNavigationView;

import java.io.File;

public class MainActivity extends AppCompatActivity {

    private FrameLayout fragmentContainer;
    private BottomNavigationView bottomNav;
    private Fragment currentFragment;
    private UIConfig uiConfig;

    private final ActivityResultLauncher<Intent> manageStorageLauncher = registerForActivityResult(
            new ActivityResultContracts.StartActivityForResult(),
            result -> {
                if (hasManageStoragePermission()) {
                    LogUtils.success("MainActivity", "存储权限已授予");
                    checkAndSetWorkFolder();
                } else {
                    LogUtils.w("MainActivity", "存储权限被拒绝");
                    Toast.makeText(this, "需要存储权限才能正常使用", Toast.LENGTH_LONG).show();
                }
            });

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        long startTime = System.currentTimeMillis();
        LogUtils.enter("MainActivity", "onCreate");

        // 确保应用在最近任务中可见
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            setTaskDescription(new ActivityManager.TaskDescription(
                getString(R.string.app_name),
                null,
                getColor(R.color.primary)
            ));
        }

        uiConfig = UIConfig.getInstance(this);
        uiConfig.applyTheme(this);

        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        CrashHandler.getInstance().init(this);
        LogUtils.init(this);

        LogUtils.separator("MainActivity", "应用启动");
        LogUtils.param("MainActivity", "版本", getVersionCode());
        LogUtils.param("MainActivity", "Android版本", Build.VERSION.RELEASE + " (API " + Build.VERSION.SDK_INT + ")");
        LogUtils.param("MainActivity", "设备", Build.MANUFACTURER + " " + Build.MODEL);
        LogUtils.param("MainActivity", "当前主题", uiConfig.getCurrentThemeName());

        fragmentContainer = findViewById(R.id.fragment_container);
        bottomNav = findViewById(R.id.bottom_navigation);

        setupBottomNavigation();
        checkPermissions();

        if (savedInstanceState == null) {
            switchToFragment(new ToolsFragment());
            bottomNav.setSelectedItemId(R.id.nav_tools);
        }

        bottomNav.setOnItemSelectedListener(item -> {
            int itemId = item.getItemId();
            Fragment newFragment = null;
            if (itemId == R.id.nav_dev) {
                newFragment = new DevFragment();
                LogUtils.action("MainActivity", "切换界面", "开发");
            } else if (itemId == R.id.nav_tools) {
                newFragment = new ToolsFragment();
                LogUtils.action("MainActivity", "切换界面", "工具");
            } else if (itemId == R.id.nav_manage) {
                newFragment = new ManageFragment();
                LogUtils.action("MainActivity", "切换界面", "管理");
            }

            if (newFragment != null) {
                switchToFragment(newFragment);
                return true;
            }
            return false;
        });

        LogUtils.exit("MainActivity", "onCreate", startTime);
    }

    private int getVersionCode() {
        try {
            return getPackageManager().getPackageInfo(getPackageName(), 0).versionCode;
        } catch (Exception e) {
            return 1;
        }
    }

    private void setupBottomNavigation() {
        try {
            int selectedColor = uiConfig.getPrimaryColor();
            int unselectedColor = uiConfig.getTextHintColor();

            android.content.res.ColorStateList colorStateList = new android.content.res.ColorStateList(
                new int[][]{
                    new int[]{android.R.attr.state_checked},
                    new int[]{-android.R.attr.state_checked}
                },
                new int[]{
                    selectedColor,
                    unselectedColor
                }
            );
            bottomNav.setItemIconTintList(colorStateList);
            bottomNav.setItemTextColor(colorStateList);
            bottomNav.setBackgroundColor(uiConfig.getSurfaceColor());

        } catch (Exception e) {
            LogUtils.e("MainActivity", "设置底部导航颜色失败: " + e.getMessage());
        }
    }

    private void checkPermissions() {
        LogUtils.enter("MainActivity", "checkPermissions");

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            if (!hasManageStoragePermission()) {
                LogUtils.w("MainActivity", "需要管理所有文件权限");
                showPermissionDialog();
            } else {
                LogUtils.success("MainActivity", "管理所有文件权限已授予");
                checkAndSetWorkFolder();
            }
        } else {
            if (ContextCompat.checkSelfPermission(this, android.Manifest.permission.WRITE_EXTERNAL_STORAGE)
                    != android.content.pm.PackageManager.PERMISSION_GRANTED) {
                LogUtils.w("MainActivity", "需要存储权限");
                showPermissionDialog();
            } else {
                LogUtils.success("MainActivity", "存储权限已授予");
                checkAndSetWorkFolder();
            }
        }

        LogUtils.exit("MainActivity", "checkPermissions", System.currentTimeMillis());
    }

    private boolean hasManageStoragePermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            return Environment.isExternalStorageManager();
        }
        return true;
    }

    private void showPermissionDialog() {
        new AlertDialog.Builder(this)
                .setTitle("需要存储权限")
                .setMessage("UIN Tool 需要管理所有文件的权限，以便导入/导出插件。\n\n请点击「授权」并允许权限。")
                .setPositiveButton("授权", (dialog, which) -> requestManageStoragePermission())
                .setNegativeButton("退出", (dialog, which) -> finish())
                .setCancelable(false)
                .show();
    }

    private void requestManageStoragePermission() {
        LogUtils.i("MainActivity", "请求存储权限");
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            Intent intent = new Intent(Settings.ACTION_MANAGE_APP_ALL_FILES_ACCESS_PERMISSION);
            intent.setData(Uri.parse("package:" + getPackageName()));
            manageStorageLauncher.launch(intent);
        } else {
            requestPermissions(new String[]{android.Manifest.permission.WRITE_EXTERNAL_STORAGE}, 100);
        }
    }

    private void checkAndSetWorkFolder() {
        try {
            String workFolder = PreferencesUtils.getWorkFolder(this);
            LogUtils.param("MainActivity", "workFolder", workFolder);

            if (workFolder == null || workFolder.isEmpty()) {
                File defaultFolder = new File("/storage/emulated/0/UIN_Tool");
                if (!defaultFolder.exists()) {
                    defaultFolder.mkdirs();
                    LogUtils.file("MainActivity", "创建工作目录", defaultFolder);
                }
                PreferencesUtils.setWorkFolder(this, defaultFolder.getAbsolutePath());
                LogUtils.success("MainActivity", "设置默认工作目录: " + defaultFolder.getAbsolutePath());
                Toast.makeText(this, "工作目录: " + defaultFolder.getAbsolutePath(), Toast.LENGTH_LONG).show();
            } else {
                File folder = new File(workFolder);
                if (!folder.exists()) {
                    folder.mkdirs();
                    LogUtils.file("MainActivity", "创建工作目录", folder);
                }
                LogUtils.i("MainActivity", "使用已有工作目录: " + workFolder);
            }
        } catch (Exception e) {
            LogUtils.ex("MainActivity", e);
            Toast.makeText(this, "创建工作目录失败: " + e.getMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    private void switchToFragment(Fragment fragment) {
        if (currentFragment != null && currentFragment.getClass() == fragment.getClass()) {
            return;
        }
        currentFragment = fragment;
        FragmentManager fm = getSupportFragmentManager();
        FragmentTransaction ft = fm.beginTransaction();
        ft.replace(R.id.fragment_container, fragment);
        ft.commit();
    }

    @Override
    protected void onResume() {
        super.onResume();
        LogUtils.d("MainActivity", "onResume");
        uiConfig.applyTheme(this);
        setupBottomNavigation();
    }

    @Override
    protected void onPause() {
        super.onPause();
        LogUtils.d("MainActivity", "onPause");
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        LogUtils.i("MainActivity", "应用退出");
    }

    @Override
    public void onBackPressed() {
        // 按返回键时，将应用移到后台而不是销毁
        // 这样可以在最近任务中看到应用
        moveTaskToBack(true);
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, String[] permissions, int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (requestCode == 100) {
            if (grantResults.length > 0 && grantResults[0] == android.content.pm.PackageManager.PERMISSION_GRANTED) {
                LogUtils.success("MainActivity", "存储权限已授予");
                checkAndSetWorkFolder();
            } else {
                LogUtils.w("MainActivity", "存储权限被拒绝");
                Toast.makeText(this, "需要存储权限才能正常使用", Toast.LENGTH_LONG).show();
                finish();
            }
        }
    }
}

package com.UIN.Tool;

import android.app.Application;
import android.content.Intent;
import android.os.Handler;
import android.os.Looper;
import android.util.Log;

import com.UIN.Tool.plugin.PluginManager;

import java.io.File;
import java.io.FileWriter;
import java.io.PrintWriter;
import java.io.StringWriter;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class UinApplication extends Application {

    private static UinApplication instance;

    static {
        Thread.setDefaultUncaughtExceptionHandler(new Thread.UncaughtExceptionHandler() {
            @Override
            public void uncaughtException(Thread thread, Throwable ex) {
                writeCrashLogImmediately(thread, ex);
                try { Thread.sleep(200); } catch (InterruptedException ignored) {}
                android.os.Process.killProcess(android.os.Process.myPid());
                System.exit(1);
            }
        });
    }

    @Override
    public void onCreate() {
        super.onCreate();
        instance = this;

        // 初始化 PluginManager
        PluginManager.getInstance(this);

        try {
            boolean hasCrashed = getSharedPreferences("crash", MODE_PRIVATE).getBoolean("just_crashed", false);
            if (hasCrashed) {
                getSharedPreferences("crash", MODE_PRIVATE).edit().putBoolean("just_crashed", false).apply();

                new Handler(Looper.getMainLooper()).postDelayed(() -> {
                    try {
                        Intent intent = new Intent(this, Class.forName("com.UIN.Tool.ui.log.LogViewerActivity"));
                        intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
                        intent.putExtra("auto_open", true);
                        startActivity(intent);
                    } catch (Exception e) {
                        e.printStackTrace();
                    }
                }, 1000);
            }
        } catch (Exception e) {
            e.printStackTrace();
        }

        Log.i("UinApplication", "应用启动");
    }

    private static void writeCrashLogImmediately(Thread thread, Throwable ex) {
        StringBuilder sb = new StringBuilder();
        sb.append("\n");
        sb.append("================== 崩溃报告 ==================\n");
        sb.append("时间: ").append(getCurrentTime()).append("\n");
        sb.append("线程: ").append(thread.getName()).append("\n");
        sb.append("异常类型: ").append(ex.getClass().getName()).append("\n");
        sb.append("异常信息: ").append(ex.getMessage()).append("\n");
        sb.append("堆栈信息:\n");

        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        ex.printStackTrace(pw);
        sb.append(sw.toString());

        Throwable cause = ex.getCause();
        if (cause != null) {
            sb.append("\n根原因:\n");
            StringWriter sw2 = new StringWriter();
            PrintWriter pw2 = new PrintWriter(sw2);
            cause.printStackTrace(pw2);
            sb.append(sw2.toString());
        }

        sb.append("================== 崩溃报告结束 ==================\n");

        try {
            File logDir = new File("/storage/emulated/0/UIN_Tool/logs");
            if (!logDir.exists()) {
                logDir.mkdirs();
            }
            String date = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(new Date());
            File logFile = new File(logDir, "crash_" + date + ".log");
            FileWriter fw = new FileWriter(logFile, true);
            fw.write(sb.toString());
            fw.close();
        } catch (Exception e) {}

        try {
            File crashFile = new File("/data/data/com.UIN.Tool/files/crash_log.txt");
            File parent = crashFile.getParentFile();
            if (parent != null && !parent.exists()) {
                parent.mkdirs();
            }
            FileWriter fw = new FileWriter(crashFile, true);
            fw.write(sb.toString());
            fw.close();
        } catch (Exception e) {}

        Log.e("CRASH", sb.toString());
    }

    private static String getCurrentTime() {
        return new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault()).format(new Date());
    }

    public static UinApplication getInstance() {
        return instance;
    }
}

package com.UIN.Tool.compiler;

import android.content.Context;
import android.os.AsyncTask;
import android.widget.Toast;

import com.UIN.Tool.utils.LogUtils;

import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.lang.reflect.Method;
import java.net.URL;
import java.net.URLClassLoader;
import java.util.ArrayList;
import java.util.List;
import java.util.zip.ZipEntry;
import java.util.zip.ZipOutputStream;

public class JavaToDexCompiler {

    private Context context;
    private OnCompileListener listener;
    private boolean useFullCompile = false;
    private String uiType = "native"; // native 或 web

    private static final String ECJ_JAR_ASSET = "compiler/ecj.jar";
    private static final String D8_JAR_ASSET = "compiler/d8.jar";

    public interface OnCompileListener {
        void onStart();
        void onProgress(String message);
        void onSuccess(File resultFile);
        void onError(String error);
    }

    public JavaToDexCompiler(Context context) { 
        this.context = context; 
    }

    public void setOnCompileListener(OnCompileListener listener) { 
        this.listener = listener; 
    }

    public void setUseFullCompile(boolean useFullCompile) {
        this.useFullCompile = useFullCompile;
    }

    public void setUiType(String uiType) {
        this.uiType = uiType;
    }

    public void compile(File javaSrcDir, File outputDir, String classpath) {
        new CompileTask(javaSrcDir, outputDir, classpath).execute();
    }

    public void packageToTpk(File projectDir, File outputTpk) {
        new PackageTask(projectDir, outputTpk).execute();
    }

    private class CompileTask extends AsyncTask<Void, String, Boolean> {
        private File javaSrcDir, outputDir, classOutputDir, dexOutputFile, jarFile;
        private String classpath, errorMessage;
        private long startTime;

        CompileTask(File javaSrcDir, File outputDir, String classpath) {
            this.javaSrcDir = javaSrcDir;
            this.outputDir = outputDir;
            this.classpath = classpath;
            this.classOutputDir = new File(outputDir, "classes");
            this.dexOutputFile = new File(outputDir, "classes.dex");
            this.jarFile = new File(outputDir, "input.jar");
        }

        @Override protected void onPreExecute() { 
            startTime = System.currentTimeMillis();
            if (listener != null) listener.onStart(); 
            LogUtils.enter("JavaToDexCompiler", "compile");
        }

        @Override protected Boolean doInBackground(Void... voids) {
            if (useFullCompile) {
                publishProgress("准备编译环境...");
                if (!compileJavaToClass()) return false;
                publishProgress("打包 JAR...");
                if (!packageJar()) return false;
                publishProgress("生成 DEX...");
                if (!convertJarToDex()) return false;
            } else {
                publishProgress("生成项目文件...");
                generateProjectFiles();
            }
            return true;
        }

        private boolean compileJavaToClass() {
            try {
                File ecjJar = copyAssetToCache(ECJ_JAR_ASSET, "ecj.jar");
                if (ecjJar == null) throw new Exception("ECJ 编译器未找到");

                URLClassLoader loader = new URLClassLoader(new URL[]{ecjJar.toURI().toURL()}, getClass().getClassLoader());
                Class<?> mainClass = loader.loadClass("org.eclipse.jdt.internal.compiler.batch.Main");

                List<String> args = new ArrayList<>();
                args.add("-d"); args.add(classOutputDir.getAbsolutePath());
                args.add("-sourcepath"); args.add(javaSrcDir.getAbsolutePath());
                args.add("-source"); args.add("1.7"); args.add("-target"); args.add("1.7");
                args.add("-noExit"); args.add("-proceedOnError");
                if (classpath != null && !classpath.isEmpty()) { 
                    args.add("-classpath"); 
                    args.add(classpath); 
                }

                List<File> javaFiles = new ArrayList<>();
                findJavaFiles(javaSrcDir, javaFiles);
                for (File f : javaFiles) args.add(f.getAbsolutePath());

                Object compiler = mainClass.getConstructor(java.io.PrintWriter.class, java.io.PrintWriter.class, boolean.class)
                        .newInstance(new java.io.PrintWriter(System.out), new java.io.PrintWriter(System.err), false);
                Method compileMethod = mainClass.getMethod("compile", String[].class);
                boolean success = (Boolean) compileMethod.invoke(compiler, (Object) args.toArray(new String[0]));

                if (!success) throw new Exception("ECJ 编译失败");
                return true;
            } catch (Exception e) {
                errorMessage = "ECJ 编译异常: " + e.getMessage();
                LogUtils.ex("JavaToDexCompiler", e);
                return false;
            }
        }

        private boolean packageJar() {
            try {
                ProcessBuilder pb = new ProcessBuilder("jar", "cf", jarFile.getAbsolutePath(), "-C", classOutputDir.getAbsolutePath(), ".");
                int exitCode = pb.start().waitFor();
                if (exitCode != 0) throw new Exception("jar 打包失败");
                return true;
            } catch (Exception e) {
                errorMessage = "jar 打包异常: " + e.getMessage();
                return false;
            }
        }

        private boolean convertJarToDex() {
            try {
                File d8Jar = copyAssetToCache(D8_JAR_ASSET, "d8.jar");
                if (d8Jar == null) throw new Exception("D8 编译器未找到");

                URLClassLoader loader = new URLClassLoader(new URL[]{d8Jar.toURI().toURL()}, getClass().getClassLoader());
                Class<?> d8Class = loader.loadClass("com.android.tools.r8.D8");
                Method mainMethod = d8Class.getMethod("main", String[].class);

                List<String> args = new ArrayList<>();
                args.add("--min-api"); args.add("21");
                args.add("--output"); args.add(outputDir.getAbsolutePath());
                args.add(jarFile.getAbsolutePath());

                mainMethod.invoke(null, (Object) args.toArray(new String[0]));
                if (!dexOutputFile.exists()) throw new Exception("D8 未生成 DEX 文件");
                return true;
            } catch (Exception e) {
                errorMessage = "D8 转换异常: " + e.getMessage();
                LogUtils.ex("JavaToDexCompiler", e);
                return false;
            }
        }

        private void generateProjectFiles() {
            try {
                if (!classOutputDir.exists()) classOutputDir.mkdirs();
                File readmeFile = new File(outputDir, "README.md");
                String readme = "# 插件编译说明\n\n" +
                        "## 手动编译步骤\n\n" +
                        "1. 将 Java 源码复制到电脑\n" +
                        "2. 使用 javac 编译: javac -d . -cp host-sdk.jar src/**/*.java\n" +
                        "3. 打包为 jar: jar cvf plugin.jar com/\n" +
                        "4. 转换为 dex: d8 --lib android.jar --min-api 21 --output . plugin.jar\n" +
                        "5. 重命名: mv classes.dex plugin.dex\n";
                FileOutputStream fos = new FileOutputStream(readmeFile);
                fos.write(readme.getBytes());
                fos.close();
                LogUtils.success("JavaToDexCompiler", "项目文件已生成: " + outputDir);
            } catch (Exception e) {
                LogUtils.ex("JavaToDexCompiler", e);
            }
        }

        private File copyAssetToCache(String assetPath, String cacheName) {
            try {
                File cacheFile = new File(context.getCacheDir(), cacheName);
                if (cacheFile.exists()) return cacheFile;
                try (java.io.InputStream is = context.getAssets().open(assetPath);
                     java.io.FileOutputStream fos = new java.io.FileOutputStream(cacheFile)) {
                    byte[] buffer = new byte[8192];
                    int len;
                    while ((len = is.read(buffer)) > 0) fos.write(buffer, 0, len);
                }
                return cacheFile;
            } catch (Exception e) { 
                LogUtils.e("JavaToDexCompiler", "复制资产失败: " + assetPath, e);
                return null; 
            }
        }

        private void findJavaFiles(File dir, List<File> result) {
            File[] files = dir.listFiles();
            if (files == null) return;
            for (File f : files) {
                if (f.isDirectory()) findJavaFiles(f, result);
                else if (f.getName().endsWith(".java")) result.add(f);
            }
        }

        @Override protected void onProgressUpdate(String... values) { 
            if (listener != null) listener.onProgress(values[0]); 
        }

        @Override protected void onPostExecute(Boolean success) { 
            LogUtils.exit("JavaToDexCompiler", "compile", startTime);
            if (success) {
                if (listener != null) listener.onSuccess(dexOutputFile);
            } else {
                if (listener != null) listener.onError(errorMessage != null ? errorMessage : "编译失败");
            }
        }
    }

    /**
     * 打包项目为 TPK 文件
     * 原生插件：包含 plugin.json, icon.png, plugin.dex, src/, res/
     * Web 插件：包含 plugin.json, icon.png, web/
     */
    private class PackageTask extends AsyncTask<Void, String, Boolean> {
        private File projectDir, outputTpk;
        private String errorMessage;

        PackageTask(File projectDir, File outputTpk) { 
            this.projectDir = projectDir; 
            this.outputTpk = outputTpk; 
        }

        @Override protected Boolean doInBackground(Void... voids) { 
            return doPackage(); 
        }

        private boolean doPackage() {
            try {
                if (outputTpk.exists()) {
                    outputTpk.delete();
                }

                File parentDir = outputTpk.getParentFile();
                if (parentDir != null && !parentDir.exists()) {
                    parentDir.mkdirs();
                }

                // 读取 plugin.json 判断插件类型
                String pluginUiType = "native";
                File jsonFile = new File(projectDir, "plugin.json");
                if (jsonFile.exists()) {
                    String json = readFileToString(jsonFile);
                    try {
                        org.json.JSONObject obj = new org.json.JSONObject(json);
                        pluginUiType = obj.optString("uiType", "native");
                    } catch (Exception e) {
                        LogUtils.e("JavaToDexCompiler", "解析 plugin.json 失败", e);
                    }
                }

                ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(outputTpk));

                // 1. 添加 plugin.json
                addFileToZip(zos, jsonFile, "plugin.json");

                // 2. 添加 icon.png
                addFileToZip(zos, new File(projectDir, "icon.png"), "icon.png");

                // 3. 根据插件类型处理
                if ("web".equals(pluginUiType)) {
                    // Web 插件：不需要 plugin.dex，只需要 web 目录
                    LogUtils.i("JavaToDexCompiler", "打包 Web 插件，跳过 DEX 文件");

                    // 添加 web 目录
                    File webDir = new File(projectDir, "web");
                    if (webDir.exists() && webDir.isDirectory()) {
                        LogUtils.i("JavaToDexCompiler", "检测到 web 目录，正在打包 Web 资源...");
                        addDirToZip(zos, webDir, "web/");
                    } else {
                        LogUtils.w("JavaToDexCompiler", "未检测到 web 目录，创建默认页面");
                        // 创建默认的 web 目录和 index.html
                        ZipEntry entry = new ZipEntry("web/index.html");
                        zos.putNextEntry(entry);
                        String defaultHtml = getDefaultHtml();
                        zos.write(defaultHtml.getBytes());
                        zos.closeEntry();
                    }
                } else {
                    // 原生插件：需要 plugin.dex
                    File dexFile = new File(projectDir, "plugin.dex");
                    if (dexFile.exists()) {
                        addFileToZip(zos, dexFile, "plugin.dex");
                    } else {
                        LogUtils.w("JavaToDexCompiler", "原生插件缺少 plugin.dex，创建占位文件");
                        ZipEntry entry = new ZipEntry("plugin.dex");
                        zos.putNextEntry(entry);
                        zos.write("// 占位文件，请替换为实际编译的 DEX".getBytes());
                        zos.closeEntry();
                    }

                    // 添加 src 目录
                    File srcDir = new File(projectDir, "src");
                    if (srcDir.exists()) {
                        addDirToZip(zos, srcDir, "src/");
                    }

                    // 添加 res 目录
                    File resDir = new File(projectDir, "res");
                    if (resDir.exists() && resDir.listFiles() != null && resDir.listFiles().length > 0) {
                        addDirToZip(zos, resDir, "res/");
                    }
                }

                zos.close();
                LogUtils.success("JavaToDexCompiler", "TPK 打包完成: " + outputTpk.getAbsolutePath());
                return true;

            } catch (Exception e) { 
                errorMessage = "打包失败: " + e.getMessage(); 
                LogUtils.ex("JavaToDexCompiler", e);
                return false; 
            }
        }

        private String getDefaultHtml() {
            return "<!DOCTYPE html>\n" +
                    "<html>\n" +
                    "<head>\n" +
                    "    <meta charset=\"UTF-8\">\n" +
                    "    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n" +
                    "    <title>Web 插件</title>\n" +
                    "    <style>\n" +
                    "        body { font-family: sans-serif; padding: 20px; text-align: center; }\n" +
                    "        button { background: #37474F; color: white; border: none; padding: 12px 24px; border-radius: 8px; margin: 10px; }\n" +
                    "    </style>\n" +
                    "</head>\n" +
                    "<body>\n" +
                    "    <h1>Web 插件</h1>\n" +
                    "    <button onclick=\"UINPlugin.callHost('toast', 'Hello from Web Plugin!')\">点我</button>\n" +
                    "    <button onclick=\"UINPlugin.callHost('finish', '')\">关闭</button>\n" +
                    "    <script>\n" +
                    "        console.log('Web 插件已加载');\n" +
                    "    </script>\n" +
                    "</body>\n" +
                    "</html>";
        }

        private void addFileToZip(ZipOutputStream zos, File file, String entryName) throws Exception {
            if (file.exists() && file.isFile()) {
                ZipEntry entry = new ZipEntry(entryName);
                zos.putNextEntry(entry);
                FileInputStream fis = new FileInputStream(file);
                byte[] buffer = new byte[8192];
                int len;
                while ((len = fis.read(buffer)) > 0) {
                    zos.write(buffer, 0, len);
                }
                fis.close();
                zos.closeEntry();
                LogUtils.d("JavaToDexCompiler", "已添加: " + entryName + " (" + file.length() + " bytes)");
            } else {
                LogUtils.w("JavaToDexCompiler", "文件不存在: " + entryName);
            }
        }

        private void addDirToZip(ZipOutputStream zos, File dir, String basePath) throws Exception {
            if (!dir.exists() || !dir.isDirectory()) return;

            File[] files = dir.listFiles();
            if (files == null) return;

            for (File file : files) {
                String entryName = basePath + file.getName();
                if (file.isDirectory()) {
                    // 添加目录条目
                    ZipEntry entry = new ZipEntry(entryName + "/");
                    zos.putNextEntry(entry);
                    zos.closeEntry();
                    // 递归处理子目录
                    addDirToZip(zos, file, entryName + "/");
                } else {
                    ZipEntry entry = new ZipEntry(entryName);
                    zos.putNextEntry(entry);
                    FileInputStream fis = new FileInputStream(file);
                    byte[] buffer = new byte[8192];
                    int len;
                    while ((len = fis.read(buffer)) > 0) {
                        zos.write(buffer, 0, len);
                    }
                    fis.close();
                    zos.closeEntry();
                    LogUtils.d("JavaToDexCompiler", "已添加: " + entryName + " (" + file.length() + " bytes)");
                }
            }
        }

        private String readFileToString(File file) {
            try {
                FileInputStream fis = new FileInputStream(file);
                byte[] data = new byte[(int) file.length()];
                fis.read(data);
                fis.close();
                return new String(data, "UTF-8");
            } catch (Exception e) {
                return "{}";
            }
        }

        @Override protected void onPostExecute(Boolean success) { 
            if (success && listener != null) {
                listener.onSuccess(outputTpk);
            } else if (listener != null) {
                listener.onError(errorMessage != null ? errorMessage : "打包失败");
            }
        }
    }
}

package com.UIN.Tool.plugin;

import android.content.Context;
import android.content.ContextWrapper;
import android.content.res.AssetManager;
import android.content.res.Resources;
import android.view.LayoutInflater;

import com.UIN.Tool.utils.LogUtils;

import java.io.File;
import java.lang.reflect.Method;

public class PluginContext extends ContextWrapper {

    private final String pluginDir;
    private AssetManager pluginAssetManager;
    private Resources pluginResources;
    private LayoutInflater pluginInflater;

    public PluginContext(Context base, String pluginDir) {
        super(base);
        this.pluginDir = pluginDir;
        initPluginResources();
    }

    private void initPluginResources() {
        try {
            AssetManager assetManager = AssetManager.class.newInstance();
            Method addAssetPath = AssetManager.class.getMethod("addAssetPath", String.class);

            addAssetPath.invoke(assetManager, pluginDir);

            File resDir = new File(pluginDir, "res");
            if (resDir.exists()) {
                addAssetPath.invoke(assetManager, resDir.getAbsolutePath());
            }

            this.pluginAssetManager = assetManager;

            Resources superRes = super.getResources();
            this.pluginResources = new Resources(assetManager, superRes.getDisplayMetrics(), superRes.getConfiguration());
            // 修复：使用 getBaseContext() 而不是 base
            this.pluginInflater = LayoutInflater.from(getBaseContext());

            LogUtils.success("PluginContext", "插件资源加载成功: " + pluginDir);
        } catch (Exception e) {
            LogUtils.w("PluginContext", "资源加载失败: " + e.getMessage());
            this.pluginAssetManager = super.getAssets();
            this.pluginResources = super.getResources();
            // 修复：使用 getBaseContext()
            this.pluginInflater = LayoutInflater.from(getBaseContext());
        }
    }

    public String getPluginDir() { 
        return pluginDir; 
    }

    public String getPluginFilePath(String relativePath) { 
        return pluginDir + "/" + relativePath; 
    }

    public boolean hasPluginFile(String relativePath) { 
        return new File(pluginDir, relativePath).exists(); 
    }

    @Override
    public AssetManager getAssets() { 
        return pluginAssetManager != null ? pluginAssetManager : super.getAssets(); 
    }

    @Override
    public Resources getResources() { 
        return pluginResources != null ? pluginResources : super.getResources(); 
    }

    @Override
    public Object getSystemService(String name) {
        if (Context.LAYOUT_INFLATER_SERVICE.equals(name)) {
            return pluginInflater;
        }
        return super.getSystemService(name);
    }
}

package com.UIN.Tool.plugin;

import android.os.Build;
import android.os.Bundle;
import android.view.View;
import android.webkit.WebChromeClient;
import android.webkit.WebSettings;
import android.webkit.WebView;
import android.webkit.WebViewClient;
import android.widget.FrameLayout;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.UIN.Tool.utils.LogUtils;

import java.io.File;

public class PluginHostActivity extends AppCompatActivity {
    public static final String EXTRA_PLUGIN_ID = "plugin_id";

    private FrameLayout container;
    private String currentPluginId;
    private WebPluginProxy webProxy;
    private WebView webView;
    private PluginManager pluginManager;
    private String currentTitle = "";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        container = new FrameLayout(this);
        container.setLayoutParams(new FrameLayout.LayoutParams(
                FrameLayout.LayoutParams.MATCH_PARENT,
                FrameLayout.LayoutParams.MATCH_PARENT
        ));
        setContentView(container);

        currentPluginId = getIntent().getStringExtra(EXTRA_PLUGIN_ID);
        if (currentPluginId == null) {
            finish();
            return;
        }

        pluginManager = PluginManager.getInstance(this);
        PluginInfo pluginInfo = pluginManager.getPluginInfo(currentPluginId);

        if (pluginInfo == null) {
            LogUtils.e("PluginHostActivity", "插件不存在: " + currentPluginId);
            Toast.makeText(this, "插件不存在: " + currentPluginId, Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        // 设置默认标题
        if (getSupportActionBar() != null) {
            getSupportActionBar().setTitle(pluginInfo.name);
            currentTitle = pluginInfo.name;
        }

        // 根据 UI 类型选择加载方式
        if ("web".equals(pluginInfo.uiType)) {
            loadWebPlugin(pluginManager, pluginInfo);
        } else {
            loadNativePlugin(pluginManager);
        }
    }

    public void setPluginTitle(String title) {
        currentTitle = title;
        if (getSupportActionBar() != null) {
            runOnUiThread(() -> {
                if (getSupportActionBar() != null) {
                    getSupportActionBar().setTitle(title);
                }
            });
        }
    }

    private void loadNativePlugin(PluginManager pluginManager) {
        View pluginView = pluginManager.getPluginView(currentPluginId, this, container);
        if (pluginView != null) {
            container.addView(pluginView);
        } else {
            LogUtils.e("PluginHostActivity", "加载原生插件失败");
            Toast.makeText(this, "加载原生插件失败", Toast.LENGTH_SHORT).show();
            finish();
        }
    }

    private void loadWebPlugin(PluginManager pluginManager, PluginInfo pluginInfo) {
        File pluginDir = pluginManager.getPluginDirFile(currentPluginId);
        if (pluginDir == null || !pluginDir.exists()) {
            LogUtils.e("PluginHostActivity", "插件目录不存在");
            Toast.makeText(this, "插件目录不存在", Toast.LENGTH_SHORT).show();
            finish();
            return;
        }

        createWebView(pluginDir, pluginInfo);
    }

    private void createWebView(File pluginDir, PluginInfo pluginInfo) {
        webView = new WebView(this);
        WebSettings settings = webView.getSettings();

        settings.setJavaScriptEnabled(true);
        settings.setJavaScriptCanOpenWindowsAutomatically(true);
        settings.setDomStorageEnabled(true);
        settings.setDatabaseEnabled(true);
        settings.setCacheMode(WebSettings.LOAD_DEFAULT);

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            settings.setMixedContentMode(WebSettings.MIXED_CONTENT_ALWAYS_ALLOW);
        }

        settings.setAllowFileAccess(true);
        settings.setAllowFileAccessFromFileURLs(true);
        settings.setAllowUniversalAccessFromFileURLs(true);
        settings.setDefaultTextEncodingName("UTF-8");
        settings.setBuiltInZoomControls(true);
        settings.setDisplayZoomControls(false);

        webView.setWebChromeClient(new WebChromeClient() {
            @Override
            public boolean onJsAlert(WebView view, String url, String message, android.webkit.JsResult result) {
                new android.app.AlertDialog.Builder(PluginHostActivity.this)
                    .setTitle("提示")
                    .setMessage(message)
                    .setPositiveButton("确定", (dialog, which) -> result.confirm())
                    .setCancelable(false)
                    .show();
                result.confirm();
                return true;
            }

            @Override
            public boolean onJsConfirm(WebView view, String url, String message, android.webkit.JsResult result) {
                new android.app.AlertDialog.Builder(PluginHostActivity.this)
                    .setTitle("确认")
                    .setMessage(message)
                    .setPositiveButton("确定", (dialog, which) -> result.confirm())
                    .setNegativeButton("取消", (dialog, which) -> result.cancel())
                    .show();
                return true;
            }
        });

        webView.setWebViewClient(new WebViewClient() {
            @Override
            public void onPageFinished(WebView view, String url) {
                super.onPageFinished(view, url);
                LogUtils.success("PluginHostActivity", "WebView 页面加载完成: " + url);
                view.evaluateJavascript("console.log('UINPlugin available:', typeof UINPlugin !== 'undefined');", null);

                // 恢复标题
                if (currentTitle != null && !currentTitle.isEmpty() && getSupportActionBar() != null) {
                    getSupportActionBar().setTitle(currentTitle);
                }
            }

            @Override
            public void onReceivedError(WebView view, int errorCode, String description, String failingUrl) {
                LogUtils.e("PluginHostActivity", "WebView 错误: " + description);
                Toast.makeText(PluginHostActivity.this, "加载失败: " + description, Toast.LENGTH_SHORT).show();
            }
        });

        PluginJSInterface jsInterface = new PluginJSInterface(this, currentPluginId, pluginInfo);
        webView.addJavascriptInterface(jsInterface, "UINPlugin");

        String indexPath = pluginDir.getAbsolutePath() + "/web/index.html";
        File indexFile = new File(indexPath);

        if (indexFile.exists()) {
            webView.loadUrl("file://" + indexPath);
            LogUtils.i("PluginHostActivity", "加载 Web 插件: " + indexPath);
        } else {
            String errorHtml = "<html><body style='text-align:center;padding:50px;font-family:sans-serif'>" +
                    "<h2>插件加载失败</h2>" +
                    "<p>找不到 web/index.html 文件</p>" +
                    "<p style='font-size:12px;color:#999'>路径: " + indexPath + "</p>" +
                    "</body></html>";
            webView.loadDataWithBaseURL("file://" + pluginDir.getAbsolutePath() + "/", errorHtml, "text/html", "UTF-8", null);
            LogUtils.e("PluginHostActivity", "入口文件不存在: " + indexPath);
        }

        container.addView(webView);
        LogUtils.success("PluginHostActivity", "Web 插件已加载: " + pluginInfo.name);
    }

    @Override
    protected void onResume() {
        super.onResume();
        if (webProxy != null) {
            webProxy.onResume();
        } else if (webView != null) {
            webView.onResume();
            webView.resumeTimers();
            webView.evaluateJavascript("if(window.dispatchEvent) window.dispatchEvent(new Event('resume'));", null);
        } else {
            PluginManager.getInstance(this).onPluginResume(currentPluginId);
        }
    }

    @Override
    protected void onPause() {
        super.onPause();
        if (webProxy != null) {
            webProxy.onPause();
        } else if (webView != null) {
            webView.onPause();
            webView.pauseTimers();
            webView.evaluateJavascript("if(window.dispatchEvent) window.dispatchEvent(new Event('pause'));", null);
        } else {
            PluginManager.getInstance(this).onPluginPause(currentPluginId);
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (webProxy != null) {
            webProxy.onDestroy();
            webProxy = null;
        } else if (webView != null) {
            webView.loadUrl("about:blank");
            webView.clearHistory();
            webView.clearCache(true);
            webView.destroy();
            webView = null;
        } else {
            PluginManager.getInstance(this).onPluginDestroy(currentPluginId);
        }
    }

    @Override
    public void onBackPressed() {
        boolean handled = false;
        if (webProxy != null) {
            handled = webProxy.onBackPressed();
        } else if (webView != null && webView.canGoBack()) {
            webView.goBack();
            handled = true;
        } else {
            handled = PluginManager.getInstance(this).onPluginBackPressed(currentPluginId);
        }
        if (!handled) {
            super.onBackPressed();
        }
    }
}

package com.UIN.Tool.plugin;

import org.json.JSONObject;

public class PluginInfo {
    public String pluginId;
    public int version;
    public String versionName;
    public int minHostVersion;
    public String name;
    public String author;
    public String description;
    public String icon;
    public String mainClass;
    public String updateUrl;
    public int apiLevel;
    public String category;      // 插件分类
    public String signature;     // 插件签名
    public String uiType;        // UI 类型: "native" 或 "web"
    public String entry;         // Web 插件的入口文件路径，如 "web/index.html"

    public static PluginInfo fromJson(String jsonString) {
        try {
            JSONObject obj = new JSONObject(jsonString);
            PluginInfo info = new PluginInfo();
            info.pluginId = obj.optString("pluginId");
            info.version = obj.optInt("version", 1);
            info.versionName = obj.optString("versionName", "1.0");
            info.minHostVersion = obj.optInt("minHostVersion", 1);
            info.name = obj.optString("name");
            info.author = obj.optString("author", "");
            info.description = obj.optString("description", "");
            info.icon = obj.optString("icon", "icon.png");
            info.mainClass = obj.optString("mainClass");
            info.updateUrl = obj.optString("updateUrl", "");
            info.apiLevel = obj.optInt("apiLevel", 21);
            info.category = obj.optString("category", "未分类");
            info.signature = obj.optString("signature", "");
            info.uiType = obj.optString("uiType", "native");
            info.entry = obj.optString("entry", "web/index.html");
            return info;
        } catch (Exception e) {
            e.printStackTrace();
            return null;
        }
    }

    public String toJson() {
        try {
            JSONObject obj = new JSONObject();
            obj.put("pluginId", pluginId);
            obj.put("version", version);
            obj.put("versionName", versionName);
            obj.put("minHostVersion", minHostVersion);
            obj.put("name", name);
            obj.put("author", author);
            obj.put("description", description);
            obj.put("icon", icon);
            obj.put("mainClass", mainClass);
            obj.put("updateUrl", updateUrl);
            obj.put("apiLevel", apiLevel);
            obj.put("category", category != null ? category : "未分类");
            obj.put("signature", signature != null ? signature : "");
            obj.put("uiType", uiType != null ? uiType : "native");
            obj.put("entry", entry != null ? entry : "web/index.html");
            return obj.toString();
        } catch (Exception e) {
            return "{}";
        }
    }
}

