                }

                runOnUiThread(() -> binding.tvStatus.setText(getString(R.string.backing_up_work_folder)));
                String workFolder = PreferencesUtils.getWorkFolder(this);
                JSONObject config = new JSONObject();
                config.put("work_folder", workFolder);
