package com.UIN.Tool.ui.tools;

import android.os.Bundle;
import android.text.Editable;
import android.text.TextWatcher;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.ExpandableListView;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import com.UIN.Tool.R;
import com.UIN.Tool.databinding.FragmentToolsCategoryBinding;
import com.UIN.Tool.plugin.PluginInfo;
import com.UIN.Tool.plugin.PluginManager;
import com.UIN.Tool.ui.common.BaseFragment;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class ToolsFragment extends BaseFragment {

    private FragmentToolsCategoryBinding binding;
    private CategoryAdapter categoryAdapter;
    private PluginManager pluginManager;

    private boolean isCategoryView = true;
    private String currentKeyword = "";
    private List<PluginInfo> currentPlugins = new ArrayList<>();

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container, @Nullable Bundle savedInstanceState) {
        binding = FragmentToolsCategoryBinding.inflate(inflater, container, false);
        return binding.getRoot();
    }

    @Override
    protected void initViews(View view) {
        // binding 已经在 onCreateView 中创建
    }

    @Override
    protected void initData() {
        if (getContext() != null) {
            pluginManager = PluginManager.getInstance(getContext());
        }
        loadData();
    }

    @Override
    protected void setupListeners() {
        if (binding == null) return;

        binding.btnSearch.setOnClickListener(v -> toggleSearch());
        binding.btnSwitchView.setOnClickListener(v -> toggleView());
        binding.btnClearSearch.setOnClickListener(v -> clearSearch());
        binding.etSearch.addTextChangedListener(new TextWatcher() {
            @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
            @Override public void onTextChanged(CharSequence s, int start, int before, int count) {}
            @Override public void afterTextChanged(Editable s) {
                currentKeyword = s.toString();
                loadData();
            }
        });
    }

    private void toggleSearch() {
        if (binding == null) return;
        if (binding.searchLayout.getVisibility() == View.GONE) {
            binding.searchLayout.setVisibility(View.VISIBLE);
            binding.etSearch.requestFocus();
        } else {
            binding.searchLayout.setVisibility(View.GONE);
            binding.etSearch.setText("");
            currentKeyword = "";
            loadData();
        }
    }

    private void toggleView() {
        if (binding == null) return;
        isCategoryView = !isCategoryView;
        binding.btnSwitchView.setImageResource(isCategoryView ? R.drawable.ic_grid_view : R.drawable.ic_list_view);
        loadData();
    }

    private void clearSearch() {
        if (binding == null) return;
        binding.etSearch.setText("");
        currentKeyword = "";
        loadData();
    }

    private void loadData() {
        if (binding == null) return;

        if (pluginManager == null && getContext() != null) {
            pluginManager = PluginManager.getInstance(getContext());
        }

        if (pluginManager == null) {
            showToast(getString(R.string.toast_no_plugins));
            return;
        }

        if (currentKeyword.isEmpty()) {
            currentPlugins = pluginManager.getInstalledPlugins();
        } else {
            currentPlugins = pluginManager.searchPlugins(currentKeyword);
        }

        if (currentPlugins == null) {
            currentPlugins = new ArrayList<>();
        }

        if (isCategoryView) {
            showCategoryView();
        } else {
            showListView();
        }

        if (currentPlugins.isEmpty() && !isSearching()) {
            // 静默处理，不显示 Toast
        } else if (currentPlugins.isEmpty() && isSearching()) {
            showToast(getString(R.string.no_search_results, currentKeyword));
        }
    }

    private boolean isSearching() {
        return !currentKeyword.isEmpty();
    }

    private void showCategoryView() {
        if (binding == null || pluginManager == null) return;

        List<String> categories = new ArrayList<>();
        Map<String, List<PluginInfo>> categoryMap = new HashMap<>();

        if (isSearching()) {
            categories.add(getString(R.string.search_results, currentPlugins.size()));
            categoryMap.put(categories.get(0), currentPlugins);
        } else {
            categories = pluginManager.getAllCategories();
            for (String category : categories) {
                if (category.equals(getString(R.string.all_category))) {
                    categoryMap.put(category, pluginManager.getInstalledPlugins());
                } else {
                    categoryMap.put(category, pluginManager.getPluginsByCategory(category));
                }
            }
        }

        categoryAdapter = new CategoryAdapter(requireContext(), categories, categoryMap,
                pluginInfo -> {
                    if (pluginManager != null) {
                        pluginManager.openPlugin(pluginInfo.pluginId, getContext());
                    }
                });
        binding.expandableListView.setAdapter(categoryAdapter);

        for (int i = 0; i < categoryAdapter.getGroupCount(); i++) {
            binding.expandableListView.expandGroup(i);
        }
    }

    private void showListView() {
        if (binding == null) return;

        List<String> categories = new ArrayList<>();
        categories.add(getString(R.string.all_plugins));
        Map<String, List<PluginInfo>> categoryMap = new HashMap<>();
        categoryMap.put(getString(R.string.all_plugins), currentPlugins);

        categoryAdapter = new CategoryAdapter(requireContext(), categories, categoryMap,
                pluginInfo -> {
                    if (pluginManager != null) {
                        pluginManager.openPlugin(pluginInfo.pluginId, getContext());
                    }
                });
        binding.expandableListView.setAdapter(categoryAdapter);
        binding.expandableListView.expandGroup(0);
    }

    @Override
    public void onResume() {
        super.onResume();
        if (getContext() != null) {
            pluginManager = PluginManager.getInstance(getContext());
        }
        loadData();
    }

    @Override
    public void onDestroyView() {
        super.onDestroyView();
        binding = null;
    }
}

package com.UIN.Tool.ui.widget;

import android.appwidget.AppWidgetManager;
import android.content.Intent;
import android.os.Bundle;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.Spinner;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.UIN.Tool.R;
import com.UIN.Tool.plugin.PluginInfo;
import com.UIN.Tool.plugin.PluginManager;
import com.UIN.Tool.utils.LogUtils;
import com.UIN.Tool.widget.UINWidgetProvider;
import com.UIN.Tool.widget.WidgetConfig;

import java.util.ArrayList;
import java.util.List;

public class WidgetConfigureActivity extends AppCompatActivity {

    private static final String TAG = "WidgetConfigure";
    private int appWidgetId = AppWidgetManager.INVALID_APPWIDGET_ID;
    private Spinner spinnerPlugin1;
    private Spinner spinnerPlugin2;
    private Spinner spinnerPlugin3;
    private Button btnConfirm;
    private List<PluginInfo> plugins = new ArrayList<>();
    private List<String> pluginNames = new ArrayList<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_widget_configure);

        setResult(RESULT_CANCELED);

        Intent intent = getIntent();
        Bundle extras = intent.getExtras();
        if (extras != null) {
            appWidgetId = extras.getInt(AppWidgetManager.EXTRA_APPWIDGET_ID,
                    AppWidgetManager.INVALID_APPWIDGET_ID);
        }

        if (appWidgetId == AppWidgetManager.INVALID_APPWIDGET_ID) {
            LogUtils.e(TAG, "无效的 appWidgetId");
            finish();
            return;
        }

        spinnerPlugin1 = findViewById(R.id.spinner_plugin1);
        spinnerPlugin2 = findViewById(R.id.spinner_plugin2);
        spinnerPlugin3 = findViewById(R.id.spinner_plugin3);
        btnConfirm = findViewById(R.id.btn_confirm);

        loadPlugins();

        btnConfirm.setOnClickListener(v -> saveWidgetConfig());
    }

    private void loadPlugins() {
        try {
            PluginManager pm = PluginManager.getInstance(this);
            plugins = pm.getInstalledPlugins();

            pluginNames.clear();
            pluginNames.add("-- 无 --");
            for (PluginInfo info : plugins) {
                pluginNames.add(info.name);
            }

            ArrayAdapter<String> adapter = new ArrayAdapter<>(this,
                    android.R.layout.simple_spinner_item, pluginNames);
            adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);

            spinnerPlugin1.setAdapter(adapter);
            spinnerPlugin2.setAdapter(adapter);
            spinnerPlugin3.setAdapter(adapter);

            // 加载保存的配置
            loadSavedConfig();

        } catch (Exception e) {
            LogUtils.e(TAG, "加载插件失败: " + e.getMessage());
            Toast.makeText(this, "加载插件失败", Toast.LENGTH_SHORT).show();
        }
    }

    private void loadSavedConfig() {
        WidgetConfig config = WidgetConfig.load(this, appWidgetId);
        if (config != null) {
            setSpinnerSelection(spinnerPlugin1, config.pluginId1);
            setSpinnerSelection(spinnerPlugin2, config.pluginId2);
            setSpinnerSelection(spinnerPlugin3, config.pluginId3);
        }
    }

    private void setSpinnerSelection(Spinner spinner, String pluginId) {
        if (pluginId == null || pluginId.isEmpty()) {
            spinner.setSelection(0);
            return;
        }

        for (int i = 0; i < plugins.size(); i++) {
            if (plugins.get(i).pluginId.equals(pluginId)) {
                spinner.setSelection(i + 1);
                return;
            }
        }
        spinner.setSelection(0);
    }

    private void saveWidgetConfig() {
        int pos1 = spinnerPlugin1.getSelectedItemPosition();
        int pos2 = spinnerPlugin2.getSelectedItemPosition();
        int pos3 = spinnerPlugin3.getSelectedItemPosition();

        String id1 = (pos1 > 0 && pos1 <= plugins.size()) ? plugins.get(pos1 - 1).pluginId : "";
        String id2 = (pos2 > 0 && pos2 <= plugins.size()) ? plugins.get(pos2 - 1).pluginId : "";
        String id3 = (pos3 > 0 && pos3 <= plugins.size()) ? plugins.get(pos3 - 1).pluginId : "";

        WidgetConfig config = new WidgetConfig(id1, id2, id3);
        config.save(this, appWidgetId);

        // 使用新的 UINWidgetProvider 刷新小部件
        UINWidgetProvider.refreshSingleWidget(this, appWidgetId);

        Intent resultValue = new Intent();
        resultValue.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, appWidgetId);
        setResult(RESULT_OK, resultValue);

        Toast.makeText(this, "小部件配置已保存", Toast.LENGTH_SHORT).show();
        finish();
    }
}

