    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LogUtils.i(TAG, "========================================");
        LogUtils.i(TAG, "onCreate called");
        LogUtils.i(TAG, "Intent: " + getIntent());
        LogUtils.i(TAG, "Intent action: " + getIntent().getAction());
        LogUtils.i(TAG, "Intent data: " + getIntent().getData());
        LogUtils.i(TAG, "Intent extras: " + getIntent().getExtras());

        // 从 Intent 中获取插件 ID
        String pluginId = getIntent().getStringExtra(UINWidgetProvider.EXTRA_PLUGIN_ID);

        LogUtils.i(TAG, "Plugin ID from intent: " + pluginId);

        if (pluginId == null || pluginId.isEmpty()) {
            LogUtils.e(TAG, "Plugin ID is null or empty");
            Toast.makeText(this, "无法获取插件ID", Toast.LENGTH_SHORT).show();
            LogUtils.i(TAG, "Finishing activity due to null plugin ID");
            finish();
            return;
        }

        LogUtils.i(TAG, "Plugin ID is valid, will execute plugin");

        // 延迟启动插件，让当前 Activity 先完成
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            LogUtils.i(TAG, "Handler delayed execution started");
            executePlugin(pluginId);
            LogUtils.i(TAG, "Finishing activity after plugin execution");
            finish();
        }, 50);
    }

    private void executePlugin(String pluginId) {
        LogUtils.i(TAG, "executePlugin called with pluginId: " + pluginId);

        try {
            LogUtils.i(TAG, "Getting PluginManager instance");
            PluginManager pluginManager = PluginManager.getInstance(this);

            LogUtils.i(TAG, "Getting plugin info for: " + pluginId);
            PluginInfo info = pluginManager.getPluginInfo(pluginId);

            if (info == null) {
                LogUtils.e(TAG, "Plugin not found: " + pluginId);
                Toast.makeText(this, "插件不存在: " + pluginId, Toast.LENGTH_SHORT).show();
                return;
            }

            LogUtils.i(TAG, "Plugin found: " + info.name);
            LogUtils.i(TAG, "Creating intent to start PluginHostActivity");

            Intent intent = new Intent(this, PluginHostActivity.class);
            intent.putExtra(PluginHostActivity.EXTRA_PLUGIN_ID, pluginId);
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);

            LogUtils.i(TAG, "Starting PluginHostActivity");
            startActivity(intent);

            LogUtils.success(TAG, "Plugin started: " + info.name);
        } catch (Exception e) {
            LogUtils.e(TAG, "Failed to execute plugin: " + e.getMessage(), e);
            Toast.makeText(this, "启动插件失败: " + e.getMessage(), Toast.LENGTH_SHORT).show();
        }
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        LogUtils.d(TAG, "onDestroy called");
        LogUtils.i(TAG, "========================================");
    }

    @Override
    protected void onResume() {
        super.onResume();
        LogUtils.d(TAG, "onResume called");
    }

    @Override
    protected void onPause() {
        super.onPause();
        LogUtils.d(TAG, "onPause called");
    }
}

package com.UIN.Tool.widget;

import android.app.PendingIntent;
import android.appwidget.AppWidgetManager;
import android.appwidget.AppWidgetProvider;
import android.content.ComponentName;
import android.content.Context;
import android.content.Intent;
import android.net.Uri;
import android.os.Build;
import android.widget.RemoteViews;

import androidx.annotation.NonNull;

import com.UIN.Tool.R;
import com.UIN.Tool.utils.LogUtils;

public class UINWidgetProvider extends AppWidgetProvider {

    private static final String TAG = "UINWidgetProvider";

    public static final String ACTION_WIDGET_ITEM_CLICKED = "com.UIN.Tool.WIDGET_ITEM_CLICKED";
    public static final String ACTION_REFRESH_WIDGET = "com.UIN.Tool.REFRESH_WIDGET";
    public static final String EXTRA_PLUGIN_ID = "extra_plugin_id";

    @Override
    public void onEnabled(Context context) {
        super.onEnabled(context);
        LogUtils.i(TAG, "Widget provider enabled");
    }

    @Override
    public void onUpdate(Context context, AppWidgetManager appWidgetManager, int[] appWidgetIds) {
        super.onUpdate(context, appWidgetManager, appWidgetIds);

        LogUtils.i(TAG, "onUpdate: " + (appWidgetIds != null ? appWidgetIds.length : 0) + " widgets");

        if (appWidgetIds == null || appWidgetIds.length == 0) {
            return;
        }

        for (int appWidgetId : appWidgetIds) {
            updateAppWidgetRemoteViews(context, appWidgetManager, appWidgetId);
        }
    }

    public static void updateAppWidgetRemoteViews(@NonNull Context context,
                                                   @NonNull AppWidgetManager appWidgetManager,
                                                   int appWidgetId) {
        if (appWidgetId == AppWidgetManager.INVALID_APPWIDGET_ID) {
            LogUtils.e(TAG, "updateAppWidgetRemoteViews: Invalid appWidgetId");
            return;
        }

        LogUtils.d(TAG, "updateAppWidgetRemoteViews: Updating widget " + appWidgetId);

        RemoteViews remoteViews = new RemoteViews(context.getPackageName(), R.layout.widget_layout);

        // 设置空视图
        remoteViews.setEmptyView(R.id.widget_list, R.id.empty_view);

        // 设置刷新按钮点击事件
        Intent refreshIntent = new Intent(context, UINWidgetProvider.class);
        refreshIntent.setAction(ACTION_REFRESH_WIDGET);
        refreshIntent.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, appWidgetId);
        refreshIntent.setData(Uri.parse(refreshIntent.toUri(Intent.URI_INTENT_SCHEME)));

        PendingIntent refreshPendingIntent = PendingIntent.getBroadcast(context, appWidgetId,
                refreshIntent, getPendingIntentFlags());
        remoteViews.setOnClickPendingIntent(R.id.btn_refresh, refreshPendingIntent);

        // 设置列表适配器
        Intent serviceIntent = new Intent(context, UINWidgetService.class);
        serviceIntent.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, appWidgetId);
        serviceIntent.setData(Uri.parse(serviceIntent.toUri(Intent.URI_INTENT_SCHEME)));
        remoteViews.setRemoteAdapter(R.id.widget_list, serviceIntent);

        // 关键修复：设置 PendingIntent 模板，使用广播接收器
        Intent templateIntent = new Intent(context, UINWidgetProvider.class);
        templateIntent.setAction(ACTION_WIDGET_ITEM_CLICKED);
        templateIntent.setData(Uri.parse("widget://click/" + appWidgetId));

        PendingIntent templatePendingIntent = PendingIntent.getBroadcast(context, appWidgetId,
                templateIntent, getPendingIntentFlags());
        remoteViews.setPendingIntentTemplate(R.id.widget_list, templatePendingIntent);

        appWidgetManager.updateAppWidget(appWidgetId, remoteViews);
        appWidgetManager.notifyAppWidgetViewDataChanged(appWidgetId, R.id.widget_list);
        LogUtils.success(TAG, "Widget " + appWidgetId + " updated successfully");
    }

    @Override
    public void onReceive(Context context, Intent intent) {
        String action = intent != null ? intent.getAction() : null;

        LogUtils.d(TAG, "onReceive called with action: " + action);

        if (action == null) {
            super.onReceive(context, intent);
            return;
        }

        if (ACTION_WIDGET_ITEM_CLICKED.equals(action)) {
            // 从 fillInIntent 中获取插件 ID
            String pluginId = intent.getStringExtra(EXTRA_PLUGIN_ID);
            LogUtils.i(TAG, "Widget item clicked, pluginId: " + pluginId);

            if (pluginId != null && !pluginId.isEmpty()) {
                // 启动透明桥梁 Activity
                Intent launchIntent = new Intent(context, WidgetClickActivity.class);
                launchIntent.putExtra(EXTRA_PLUGIN_ID, pluginId);
                launchIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
                context.startActivity(launchIntent);
                LogUtils.i(TAG, "Started WidgetClickActivity for plugin: " + pluginId);
            } else {
                LogUtils.e(TAG, "Plugin ID is null");
            }
        } else if (ACTION_REFRESH_WIDGET.equals(action)) {
            int appWidgetId = intent.getIntExtra(AppWidgetManager.EXTRA_APPWIDGET_ID,
                    AppWidgetManager.INVALID_APPWIDGET_ID);
            LogUtils.d(TAG, "Refresh widget: " + appWidgetId);

            if (appWidgetId != AppWidgetManager.INVALID_APPWIDGET_ID) {
                refreshSingleWidget(context, appWidgetId);
            } else {
                refreshAllWidgets(context);
            }
        } else {
            super.onReceive(context, intent);
        }
    }

    public static void refreshAllWidgets(Context context) {
        LogUtils.i(TAG, "refreshAllWidgets called");

        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(context);
        ComponentName componentName = new ComponentName(context, UINWidgetProvider.class);
        int[] appWidgetIds = appWidgetManager.getAppWidgetIds(componentName);

        if (appWidgetIds != null && appWidgetIds.length > 0) {
            for (int appWidgetId : appWidgetIds) {
                refreshSingleWidget(context, appWidgetId);
            }
        }
    }

    public static void refreshSingleWidget(Context context, int appWidgetId) {
        LogUtils.d(TAG, "refreshSingleWidget called for widget " + appWidgetId);

        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(context);
        updateAppWidgetRemoteViews(context, appWidgetManager, appWidgetId);
    }

    public static void sendIntentToRefreshAllWidgets(Context context) {
        LogUtils.i(TAG, "sendIntentToRefreshAllWidgets called");

        Intent intent = new Intent(ACTION_REFRESH_WIDGET);
        intent.setClass(context, UINWidgetProvider.class);
        intent.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, AppWidgetManager.INVALID_APPWIDGET_ID);
        context.sendBroadcast(intent);
    }

    private static int getPendingIntentFlags() {
        int flags = PendingIntent.FLAG_UPDATE_CURRENT;
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            flags |= PendingIntent.FLAG_IMMUTABLE;
        }
        return flags;
    }

    @Override
    public void onDeleted(Context context, int[] appWidgetIds) {
        super.onDeleted(context, appWidgetIds);
        if (appWidgetIds != null) {
            for (int appWidgetId : appWidgetIds) {
                WidgetConfig.delete(context, appWidgetId);
            }
            LogUtils.i(TAG, "Widgets deleted: " + appWidgetIds.length);
        }
    }

    @Override
    public void onDisabled(Context context) {
        super.onDisabled(context);
        LogUtils.i(TAG, "Widget provider disabled");
    }
}

package com.UIN.Tool.widget;

import android.content.Context;
import android.content.SharedPreferences;

import androidx.annotation.Nullable;

public class WidgetConfig {

    private static final String PREF_NAME = "uin_widget_prefs";

    public String pluginId1;
    public String pluginId2;
    public String pluginId3;

    public WidgetConfig() {
        this.pluginId1 = "";
        this.pluginId2 = "";
        this.pluginId3 = "";
    }

    public WidgetConfig(String id1, String id2, String id3) {
        this.pluginId1 = id1 != null ? id1 : "";
        this.pluginId2 = id2 != null ? id2 : "";
        this.pluginId3 = id3 != null ? id3 : "";
    }

    public boolean hasSelectedPlugins() {
        return !pluginId1.isEmpty() || !pluginId2.isEmpty() || !pluginId3.isEmpty();
    }

    public void save(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        String key = "widget_" + appWidgetId;
        prefs.edit()
                .putString(key + "_1", pluginId1)
                .putString(key + "_2", pluginId2)
                .putString(key + "_3", pluginId3)
                .apply();
    }

    @Nullable
    public static WidgetConfig load(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        String key = "widget_" + appWidgetId;

        String id1 = prefs.getString(key + "_1", "");
        String id2 = prefs.getString(key + "_2", "");
        String id3 = prefs.getString(key + "_3", "");

        if (id1.isEmpty() && id2.isEmpty() && id3.isEmpty()) {
            return null;
        }

        return new WidgetConfig(id1, id2, id3);
    }

    public static void delete(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        String key = "widget_" + appWidgetId;
        prefs.edit()
                .remove(key + "_1")
                .remove(key + "_2")
                .remove(key + "_3")
                .apply();
    }
}

package com.UIN.Tool.widget;

import android.appwidget.AppWidgetManager;
import android.content.Context;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.widget.RemoteViews;
import android.widget.RemoteViewsService;

import com.UIN.Tool.R;
import com.UIN.Tool.plugin.PluginInfo;
import com.UIN.Tool.plugin.PluginManager;
import com.UIN.Tool.utils.LogUtils;

import java.io.File;
import java.util.ArrayList;
import java.util.List;

public class UINWidgetService extends RemoteViewsService {

    private static final String TAG = "UINWidgetService";

    @Override
    public RemoteViewsFactory onGetViewFactory(Intent intent) {
        int appWidgetId = intent.getIntExtra(AppWidgetManager.EXTRA_APPWIDGET_ID,
                AppWidgetManager.INVALID_APPWIDGET_ID);
        LogUtils.i(TAG, "onGetViewFactory called for widget " + appWidgetId);
        return new WidgetRemoteViewsFactory(getApplicationContext(), appWidgetId);
    }

    static class WidgetRemoteViewsFactory implements RemoteViewsService.RemoteViewsFactory {

        private final Context context;
        private final int appWidgetId;
        private final List<PluginInfo> plugins = new ArrayList<>();
        private PluginManager pluginManager;
        private static final String FACTORY_TAG = "WidgetRemoteViewsFactory";

        WidgetRemoteViewsFactory(Context context, int appWidgetId) {
            this.context = context;
            this.appWidgetId = appWidgetId;
        }

        @Override
        public void onCreate() {
            LogUtils.d(FACTORY_TAG, "onCreate for widget " + appWidgetId);
            pluginManager = PluginManager.getInstance(context);
        }

        @Override
        public void onDataSetChanged() {
            LogUtils.d(FACTORY_TAG, "onDataSetChanged for widget " + appWidgetId);

            plugins.clear();

            if (pluginManager == null) {
                pluginManager = PluginManager.getInstance(context);
            }

            pluginManager.refreshWorkFolder();
            List<PluginInfo> installedPlugins = pluginManager.getInstalledPlugins();

            WidgetConfig config = WidgetConfig.load(context, appWidgetId);
            if (config != null && config.hasSelectedPlugins()) {
                addPluginById(config.pluginId1);
                addPluginById(config.pluginId2);
                addPluginById(config.pluginId3);
            } else {
                plugins.addAll(installedPlugins);
            }

            LogUtils.i(FACTORY_TAG, "Loaded " + plugins.size() + " plugins for widget " + appWidgetId);
        }

        private void addPluginById(String pluginId) {
            if (pluginId != null && !pluginId.isEmpty()) {
                PluginInfo info = pluginManager.getPluginInfo(pluginId);
                if (info != null) {
                    plugins.add(info);
                }
            }
        }

        @Override
        public void onDestroy() {
            LogUtils.d(FACTORY_TAG, "onDestroy for widget " + appWidgetId);
            plugins.clear();
        }

        @Override
        public int getCount() {
            return plugins.size();
        }

        @Override
        public RemoteViews getViewAt(int position) {
            if (position < 0 || position >= plugins.size()) {
                return null;
            }

            PluginInfo plugin = plugins.get(position);
            RemoteViews views = new RemoteViews(context.getPackageName(), R.layout.widget_list_item);

            views.setTextViewText(R.id.widget_item_text, plugin.name);

            Bitmap icon = getPluginIcon(plugin);
            if (icon != null) {
                views.setImageViewBitmap(R.id.widget_item_icon, icon);
            } else {
                views.setImageViewResource(R.id.widget_item_icon, R.drawable.ic_plugin_default);
            }

            // 关键：fillInIntent 必须设置与模板相同的 action
            Intent fillInIntent = new Intent();
            fillInIntent.setAction(UINWidgetProvider.ACTION_WIDGET_ITEM_CLICKED);
            fillInIntent.putExtra(UINWidgetProvider.EXTRA_PLUGIN_ID, plugin.pluginId);
            views.setOnClickFillInIntent(R.id.widget_item_layout, fillInIntent);

            LogUtils.d(FACTORY_TAG, "Configured view for position " + position + 
                    ", pluginId: " + plugin.pluginId + ", action: " + fillInIntent.getAction());

            return views;
        }

        private Bitmap getPluginIcon(PluginInfo plugin) {
            try {
                File pluginDir = pluginManager.getPluginDirFile(plugin.pluginId);
                if (pluginDir != null && pluginDir.exists()) {
                    String iconPath = plugin.icon != null && !plugin.icon.isEmpty() ? plugin.icon : "icon.png";
                    File iconFile = new File(pluginDir, iconPath);
                    if (iconFile.exists()) {
                        BitmapFactory.Options options = new BitmapFactory.Options();
                        options.inSampleSize = 2;
                        Bitmap bitmap = BitmapFactory.decodeFile(iconFile.getAbsolutePath(), options);
                        if (bitmap != null) {
                            return Bitmap.createScaledBitmap(bitmap, 64, 64, true);
                        }
                    }
                }
            } catch (Exception e) {
                LogUtils.e(FACTORY_TAG, "Failed to load icon: " + e.getMessage());
            }
            return null;
        }

        @Override
        public RemoteViews getLoadingView() {
            return null;
        }

        @Override
        public int getViewTypeCount() {
            return 1;
        }

        @Override
        public long getItemId(int position) {
            return position;
        }

        @Override
        public boolean hasStableIds() {
            return true;
        }
    }
}

package com.UIN.Tool.widget;

import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.os.Handler;
import android.os.Looper;
import android.os.SystemClock;

import com.UIN.Tool.utils.LogUtils;

public class SystemEventReceiver extends BroadcastReceiver {

    private static final String TAG = "SystemEventReceiver";

    @Override
    public void onReceive(Context context, Intent intent) {
        if (intent == null) {
            return;
        }

        String action = intent.getAction();
        long uptime = SystemClock.uptimeMillis();

        LogUtils.i(TAG, "Received intent at " + uptime + "ms: " + action);

        if (action == null) {
            return;
        }

        switch (action) {
            case Intent.ACTION_BOOT_COMPLETED:
            case Intent.ACTION_MY_PACKAGE_REPLACED:
                // 延迟刷新，确保系统完全启动
                new Handler(Looper.getMainLooper()).postDelayed(() -> {
                    LogUtils.i(TAG, "Refreshing widgets after system event: " + action);
                    UINWidgetProvider.sendIntentToRefreshAllWidgets(context);
                    Widget1x1Provider.sendRefreshIntent(context);
                }, 5000);
                break;

            default:
                LogUtils.d(TAG, "Unhandled action: " + action);
                break;
        }
    }
}

package com.UIN.Tool.ui.widget;

import android.appwidget.AppWidgetManager;
import android.content.Intent;
import android.os.Bundle;
import android.widget.ArrayAdapter;

import com.UIN.Tool.R;
import com.UIN.Tool.databinding.ActivityWidgetShortcutConfigureBinding;
import com.UIN.Tool.plugin.PluginInfo;
import com.UIN.Tool.plugin.PluginManager;
import com.UIN.Tool.ui.common.BaseActivity;
import com.UIN.Tool.widget.Widget1x1Config;

import java.util.ArrayList;
import java.util.List;

/**
 * 1x1 小部件配置界面。
 * 用户选择一个插件，该小部件将作为该插件的桌面快捷方式。
 */
public class Widget1x1ConfigureActivity extends BaseActivity {

    private ActivityWidgetShortcutConfigureBinding binding;
    private int appWidgetId = AppWidgetManager.INVALID_APPWIDGET_ID;
    private List<PluginInfo> plugins = new ArrayList<>();
    private List<String> pluginNames = new ArrayList<>();

    @Override
    protected int getLayoutResourceId() {
        return R.layout.activity_widget_shortcut_configure;
    }

    @Override
    protected void initViews() {
        binding = ActivityWidgetShortcutConfigureBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());
        setupToolbar(binding.toolbar, getString(R.string.widget_1x1_config_title), true);
    }

    @Override
    protected void initData() {
        Intent intent = getIntent();
        Bundle extras = intent.getExtras();
        if (extras != null) {
            appWidgetId = extras.getInt(AppWidgetManager.EXTRA_APPWIDGET_ID,
                    AppWidgetManager.INVALID_APPWIDGET_ID);
        }

        if (appWidgetId == AppWidgetManager.INVALID_APPWIDGET_ID) {
            finish();
            return;
        }

        loadPlugins();
        loadSavedConfig();
    }

    @Override
    protected void setupListeners() {
        binding.btnConfirm.setOnClickListener(v -> saveAndFinish());
        binding.btnSkip.setOnClickListener(v -> skipAndFinish());
    }

    private void loadPlugins() {
        try {
            PluginManager pm = PluginManager.getInstance(this);
            plugins = pm.getInstalledPlugins();

            pluginNames.clear();
            pluginNames.add(getString(R.string.widget_1x1_launch_main));
            for (PluginInfo info : plugins) {
                pluginNames.add(info.name);
            }

            ArrayAdapter<String> adapter = new ArrayAdapter<>(this,
                    android.R.layout.simple_spinner_item, pluginNames);
            adapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);

            binding.spinnerPlugin.setAdapter(adapter);

        } catch (Exception e) {
            showToast(getString(R.string.toast_import_failed, e.getMessage()));
        }
    }

    private void loadSavedConfig() {
        Widget1x1Config config = Widget1x1Config.load(this, appWidgetId);
        if (config != null && config.hasPlugin()) {
            for (int i = 0; i < plugins.size(); i++) {
                if (plugins.get(i).pluginId.equals(config.pluginId)) {
                    binding.spinnerPlugin.setSelection(i + 1);
                    return;
                }
            }
        }
    }

    private void saveAndFinish() {
        int pos = binding.spinnerPlugin.getSelectedItemPosition();
        String pluginId = "";
        if (pos > 0 && pos <= plugins.size()) {
            pluginId = plugins.get(pos - 1).pluginId;
        }

        Widget1x1Config config = new Widget1x1Config(pluginId);
        config.save(this, appWidgetId);

        // 刷新小部件
        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(this);
        com.UIN.Tool.widget.Widget1x1Provider.updateAppWidget(this, appWidgetManager, appWidgetId);

        Intent resultValue = new Intent();
        resultValue.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, appWidgetId);
        setResult(RESULT_OK, resultValue);

        showToast(getString(R.string.widget_1x1_config_saved));
        finish();
    }

    private void skipAndFinish() {
        // 不选择插件，保持默认（打开主界面）
        Widget1x1Config config = new Widget1x1Config("");
        config.save(this, appWidgetId);

        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(this);
        com.UIN.Tool.widget.Widget1x1Provider.updateAppWidget(this, appWidgetManager, appWidgetId);

        Intent resultValue = new Intent();
        resultValue.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, appWidgetId);
        setResult(RESULT_OK, resultValue);
        finish();
    }
}

