package com.UIN.Tool.utils;

import android.content.Context;
import android.content.res.AssetManager;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.util.ArrayList;
import java.util.List;

public class CompilerUtils {

    /**
     * 从 assets 复制文件到缓存目录
     */
    public static File copyAssetToCache(Context context, String assetPath, String cacheFileName) {
        try {
            File cacheFile = new File(context.getCacheDir(), cacheFileName);
            if (cacheFile.exists()) {
                return cacheFile;
            }

            // 确保父目录存在
            File parentDir = cacheFile.getParentFile();
            if (parentDir != null && !parentDir.exists()) {
                parentDir.mkdirs();
            }

            AssetManager assetManager = context.getAssets();
            InputStream is = assetManager.open(assetPath);
            OutputStream os = new FileOutputStream(cacheFile);

            byte[] buffer = new byte[8192];
            int length;
            while ((length = is.read(buffer)) > 0) {
                os.write(buffer, 0, length);
            }

            os.close();
            is.close();

            return cacheFile;
        } catch (IOException e) {
            e.printStackTrace();
            return null;
        }
    }

    /**
     * 递归查找所有 .java 文件
     */
    public static void findJavaFiles(File dir, List<File> result) {
        if (dir == null || !dir.exists()) return;
        File[] files = dir.listFiles();
        if (files == null) return;
        for (File file : files) {
            if (file.isDirectory()) {
                findJavaFiles(file, result);
            } else if (file.getName().endsWith(".java")) {
                result.add(file);
            }
        }
    }

    /**
     * 递归查找所有 .class 文件
     */
    public static void findClassFiles(File dir, List<File> result) {
        if (dir == null || !dir.exists()) return;
        File[] files = dir.listFiles();
        if (files == null) return;
        for (File file : files) {
            if (file.isDirectory()) {
                findClassFiles(file, result);
            } else if (file.getName().endsWith(".class")) {
                result.add(file);
            }
        }
    }

    /**
     * 递归删除目录
     */
    public static boolean deleteDir(File dir) {
        if (dir == null || !dir.exists()) return false;
        File[] files = dir.listFiles();
        if (files != null) {
            for (File file : files) {
                if (file.isDirectory()) {
                    deleteDir(file);
                } else {
                    file.delete();
                }
            }
        }
        return dir.delete();
    }

    /**
     * 确保目录存在
     */
    public static void ensureDir(File dir) {
        if (dir != null && !dir.exists()) {
            dir.mkdirs();
        }
    }
}

package com.UIN.Tool.utils;

import android.content.ComponentName;
import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Build;
import android.os.Process;
import android.util.Log;

import java.io.File;
import java.io.FileWriter;
import java.io.PrintWriter;
import java.io.StringWriter;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;

public class CrashHandler implements Thread.UncaughtExceptionHandler {

    private static final String TAG = "CrashHandler";
    private static CrashHandler instance;
    private Context context;
    private Thread.UncaughtExceptionHandler defaultHandler;

    private CrashHandler() {}

    public static CrashHandler getInstance() {
        if (instance == null) {
            instance = new CrashHandler();
        }
        return instance;
    }

    public void init(Context context) {
        this.context = context.getApplicationContext();
        defaultHandler = Thread.getDefaultUncaughtExceptionHandler();
        Thread.setDefaultUncaughtExceptionHandler(this);

        // 写入启动日志到多个位置
        String startLog = "=== 应用启动 ===\n" +
                "设备: " + Build.MANUFACTURER + " " + Build.MODEL + "\n" +
                "Android: " + Build.VERSION.RELEASE + " (API " + Build.VERSION.SDK_INT + ")\n" +
                "时间: " + getCurrentTime() + "\n" +
                "=================\n";

        writeToInternalLog(startLog);
        writeToExternalLog(startLog);

        // 清除崩溃标记
        setCrashFlag(false);

        Log.i(TAG, "CrashHandler 初始化完成");
    }

    @Override
    public void uncaughtException(Thread thread, Throwable ex) {
        // 标记发生了崩溃
        setCrashFlag(true);

        // 获取详细崩溃日志
        String crashLog = getDetailedCrashLog(thread, ex);

        // 写入到多个位置
        writeToInternalLog(crashLog);
        writeToExternalLog(crashLog);

        // 也尝试写入 Logcat
        Log.e(TAG, "========== 应用崩溃 ==========");
        Log.e(TAG, "线程: " + thread.getName());
        Log.e(TAG, "异常: " + ex.getMessage());
        Log.e(TAG, Log.getStackTraceString(ex));

        // 延迟确保日志写入完成
        try {
            Thread.sleep(500);
        } catch (InterruptedException ignored) {}

        // 重启应用
        restartApp();

        // 杀死进程
        Process.killProcess(Process.myPid());
        System.exit(1);
    }

    private void setCrashFlag(boolean crashed) {
        try {
            SharedPreferences prefs = context.getSharedPreferences("crash", Context.MODE_PRIVATE);
            prefs.edit().putBoolean("just_crashed", crashed).apply();
        } catch (Exception e) {
            Log.e(TAG, "设置崩溃标记失败", e);
        }
    }

    private String getDetailedCrashLog(Thread thread, Throwable ex) {
        StringBuilder sb = new StringBuilder();
        sb.append("\n");
        sb.append("================== 崩溃报告 ==================\n");
        sb.append("时间: ").append(getCurrentTime()).append("\n");
        sb.append("线程: ").append(thread.getName()).append("\n");
        sb.append("线程ID: ").append(thread.getId()).append("\n");
        sb.append("线程优先级: ").append(thread.getPriority()).append("\n");
        sb.append("异常类型: ").append(ex.getClass().getName()).append("\n");
        sb.append("异常信息: ").append(ex.getMessage()).append("\n");
        sb.append("\n堆栈信息:\n");

        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        ex.printStackTrace(pw);
        sb.append(sw.toString());

        // 获取导致异常的根原因
        Throwable cause = ex.getCause();
        if (cause != null && cause != ex) {
            sb.append("\n根原因:\n");
            StringWriter sw2 = new StringWriter();
            PrintWriter pw2 = new PrintWriter(sw2);
            cause.printStackTrace(pw2);
            sb.append(sw2.toString());
        }

        sb.append("================== 崩溃报告结束 ==================\n");

        return sb.toString();
    }

    private void writeToInternalLog(String log) {
        try {
            File logFile = new File(context.getFilesDir(), "crash_log.txt");
            FileWriter fw = new FileWriter(logFile, true);
            fw.write(log);
            fw.write("\n");
            fw.close();

            // 限制文件大小
            if (logFile.length() > 1024 * 1024) {
                truncateLogFile(logFile);
            }
        } catch (Exception e) {
            Log.e(TAG, "写入内部日志失败", e);
        }
    }

    private void writeToExternalLog(String log) {
        try {
            File logDir = new File("/storage/emulated/0/UIN_Tool/logs");
            if (!logDir.exists()) {
                logDir.mkdirs();
            }
            String date = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(new Date());
            File logFile = new File(logDir, "crash_" + date + ".log");
            FileWriter fw = new FileWriter(logFile, true);
            fw.write(log);
            fw.write("\n");
            fw.close();
        } catch (Exception e) {
            // 无法写入外部存储，忽略
            Log.e(TAG, "写入外部日志失败", e);
        }
    }

    private void truncateLogFile(File logFile) {
        try {
            if (logFile.length() > 500 * 1024) {
                // 保留最后 50KB
                java.io.RandomAccessFile raf = new java.io.RandomAccessFile(logFile, "rw");
                long length = raf.length();
                raf.seek(length - 50 * 1024);
                byte[] buffer = new byte[50 * 1024];
                raf.read(buffer);
                raf.setLength(0);
                raf.write(buffer);
                raf.close();
            }
        } catch (Exception e) {
            Log.e(TAG, "截断日志文件失败", e);
        }
    }

    private void restartApp() {
        try {
            // 先尝试打开日志界面
            Intent intent = new Intent();
            intent.setClassName(context, "com.UIN.Tool.ui.log.LogViewerActivity");
            intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
            intent.putExtra("auto_open", true);
            context.startActivity(intent);
        } catch (Exception e1) {
            try {
                // 如果失败，尝试打开主界面
                Intent intent = new Intent();
                intent.setClassName(context, "com.UIN.Tool.MainActivity");
                intent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
                context.startActivity(intent);
            } catch (Exception e2) {
                Log.e(TAG, "重启应用失败", e2);
            }
        }
    }

    private String getCurrentTime() {
        return new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault()).format(new Date());
    }
}

package com.UIN.Tool.utils;

import android.content.ContentResolver;
import android.content.Context;
import android.net.Uri;
import android.util.Log;

import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.InputStream;
import java.util.zip.ZipEntry;
import java.util.zip.ZipInputStream;

public class FileUtils {
    private static final String TAG = "FileUtils";

    /**
     * 从 Uri 复制文件到目标路径
     */
    public static boolean copyUriToFile(Context context, Uri sourceUri, File destFile) {
        try {
            ContentResolver resolver = context.getContentResolver();
            InputStream inputStream = resolver.openInputStream(sourceUri);
            if (inputStream == null) return false;

            FileOutputStream outputStream = new FileOutputStream(destFile);
            byte[] buffer = new byte[8192];
            int length;
            while ((length = inputStream.read(buffer)) > 0) {
                outputStream.write(buffer, 0, length);
            }
            outputStream.close();
            inputStream.close();
            return true;
        } catch (Exception e) {
            Log.e(TAG, "copyUriToFile error", e);
            return false;
        }
    }

    /**
     * 解压 ZIP 文件到目标目录
     */
    public static boolean unzip(File zipFile, File destDir) {
        try {
            if (!destDir.exists()) destDir.mkdirs();

            ZipInputStream zis = new ZipInputStream(new FileInputStream(zipFile));
            ZipEntry entry;
            byte[] buffer = new byte[8192];

            while ((entry = zis.getNextEntry()) != null) {
                File targetFile = new File(destDir, entry.getName());

                if (entry.isDirectory()) {
                    targetFile.mkdirs();
                } else {
                    targetFile.getParentFile().mkdirs();
                    FileOutputStream fos = new FileOutputStream(targetFile);
                    int len;
                    while ((len = zis.read(buffer)) > 0) {
                        fos.write(buffer, 0, len);
                    }
                    fos.close();
                }
                zis.closeEntry();
            }
            zis.close();
            return true;
        } catch (Exception e) {
            Log.e(TAG, "unzip error", e);
            return false;
        }
    }

    /**
     * 递归删除目录
     */
    public static boolean deleteDir(File dir) {
        if (dir == null || !dir.exists()) return false;
        if (dir.isDirectory()) {
            File[] children = dir.listFiles();
            if (children != null) {
                for (File child : children) {
                    deleteDir(child);
                }
            }
        }
        return dir.delete();
    }

    /**
     * 复制目录
     */
    public static boolean copyDir(File srcDir, File destDir) {
        try {
            if (!srcDir.exists()) return false;
            if (!destDir.exists()) destDir.mkdirs();

            for (File srcFile : srcDir.listFiles()) {
                File destFile = new File(destDir, srcFile.getName());
                if (srcFile.isDirectory()) {
                    copyDir(srcFile, destFile);
                } else {
                    FileInputStream fis = new FileInputStream(srcFile);
                    FileOutputStream fos = new FileOutputStream(destFile);
                    byte[] buffer = new byte[8192];
                    int len;
                    while ((len = fis.read(buffer)) > 0) {
                        fos.write(buffer, 0, len);
                    }
                    fis.close();
                    fos.close();
                }
            }
            return true;
        } catch (Exception e) {
            Log.e(TAG, "copyDir error", e);
            return false;
        }
    }

    /**
     * 读取文件内容为字符串
     */
    public static String readFileToString(File file) {
        try {
            FileInputStream fis = new FileInputStream(file);
            byte[] data = new byte[(int) file.length()];
            fis.read(data);
            fis.close();
            return new String(data, "UTF-8");
        } catch (Exception e) {
            return null;
        }
    }
}

package com.UIN.Tool.utils;

import android.content.Context;
import android.os.Build;

import java.io.BufferedReader;
import java.io.File;
import java.io.FileOutputStream;
import java.io.FileReader;
import java.io.PrintWriter;
import java.io.StringWriter;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class LogUtils {

    private static File logFile;
    private static boolean isInitialized = false;
    private static final int MAX_LOG_SIZE = 2 * 1024 * 1024; // 2MB
    private static final int MAX_LOG_LINES = 2000;
    private static final String LOG_DIR = "/storage/emulated/0/UIN_Tool/logs";

    public static void init(Context context) {
        if (isInitialized) return;
        try {
            File logDir = new File(LOG_DIR);
            if (!logDir.exists()) {
                logDir.mkdirs();
            }

            // 使用日期作为文件名，避免覆盖
            String date = new SimpleDateFormat("yyyy-MM-dd", Locale.getDefault()).format(new Date());
            logFile = new File(logDir, "uin_tool_" + date + ".log");

            if (!logFile.exists()) {
                logFile.createNewFile();
            }

            String time = getCurrentTime();
            writeLog("══════════════════════════════════════════════════");
            writeLog("  UIN Tool 日志开始");
            writeLog("  时间: " + time);
            writeLog("  设备: " + Build.MANUFACTURER + " " + Build.MODEL);
            writeLog("  Android: " + Build.VERSION.RELEASE + " (API " + Build.VERSION.SDK_INT + ")");
            writeLog("══════════════════════════════════════════════════");
            isInitialized = true;
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static String getCurrentTime() {
        return new SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.getDefault()).format(new Date());
    }

    private static synchronized void writeLog(String logLine) {
        if (logFile == null) return;
        try {
            FileOutputStream fos = new FileOutputStream(logFile, true);
            fos.write((logLine + "\n").getBytes());
            fos.close();
            if (logFile.length() > MAX_LOG_SIZE) {
                truncateLog();
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static void truncateLog() {
        try {
            File tempFile = new File(logFile.getParent(), "log_temp.txt");
            BufferedReader reader = new BufferedReader(new FileReader(logFile));
            List<String> lines = new ArrayList<>();
            String line;
            while ((line = reader.readLine()) != null) {
                lines.add(line);
            }
            reader.close();
            int keepLines = Math.min(MAX_LOG_LINES, lines.size());
            int startIndex = lines.size() - keepLines;
            FileOutputStream fos = new FileOutputStream(logFile);
            for (int i = startIndex; i < lines.size(); i++) {
                fos.write((lines.get(i) + "\n").getBytes());
            }
            fos.close();
            fos = new FileOutputStream(logFile, true);
            fos.write(("\n... 日志已截断，保留最近 " + keepLines + " 行 ...\n").getBytes());
            fos.close();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private static String formatFileSize(long size) {
        if (size < 1024) return size + " B";
        if (size < 1024 * 1024) return String.format("%.2f KB", size / 1024.0);
        return String.format("%.2f MB", size / (1024.0 * 1024.0));
    }

    // ==================== 基础日志方法 ====================

    public static void d(String tag, String message) {
        String log = getCurrentTime() + " [DEBUG][ " + tag + " ] " + message;
        System.out.println(log);
        writeLog(log);
    }

    public static void i(String tag, String message) {
        String log = getCurrentTime() + " [INFO ][ " + tag + " ] " + message;
        System.out.println(log);
        writeLog(log);
    }

    public static void w(String tag, String message) {
        String log = getCurrentTime() + " [WARN ][ " + tag + " ] ⚠ " + message;
        System.out.println(log);
        writeLog(log);
    }

    public static void e(String tag, String message) {
        String log = getCurrentTime() + " [ERROR][ " + tag + " ] ✗ " + message;
        System.err.println(log);
        writeLog(log);
    }

    public static void e(String tag, String message, Throwable throwable) {
        String log = getCurrentTime() + " [ERROR][ " + tag + " ] ✗ " + message + " - " + throwable.getMessage();
        System.err.println(log);
        writeLog(log);
        ex(tag, throwable);
    }

    public static void ex(String tag, Throwable throwable) {
        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        throwable.printStackTrace(pw);
        String[] lines = sw.toString().split("\n");
        for (int i = 0; i < Math.min(lines.length, 15); i++) {
            writeLog(getCurrentTime() + " [ERROR][ " + tag + " ]     " + lines[i]);
        }
    }

    public static void success(String tag, String message) {
        String log = getCurrentTime() + " [SUCCESS][ " + tag + " ] ✓ " + message;
        System.out.println(log);
        writeLog(log);
    }

    // ==================== 高级日志方法 ====================

    public static void enter(String tag, String methodName) {
        d(tag, "→ " + methodName + "() 进入");
    }

    public static void exit(String tag, String methodName, long startTime) {
        long cost = System.currentTimeMillis() - startTime;
        d(tag, "← " + methodName + "() 退出, 耗时: " + cost + "ms");
    }

    public static void separator(String tag, String title) {
        writeLog(getCurrentTime() + " [INFO ][ " + tag + " ] ══════════════════════════════════════════════════");
        if (title != null && !title.isEmpty()) {
            writeLog(getCurrentTime() + " [INFO ][ " + tag + " ]   " + title);
            writeLog(getCurrentTime() + " [INFO ][ " + tag + " ] ──────────────────────────────────────────────────");
        }
    }

    public static void param(String tag, String key, String value) {
        d(tag, "  📌 " + key + " = " + value);
    }

    public static void param(String tag, String key, int value) {
        d(tag, "  📌 " + key + " = " + value);
    }

    public static void param(String tag, String key, long value) {
        d(tag, "  📌 " + key + " = " + value);
    }

    public static void param(String tag, String key, boolean value) {
        d(tag, "  📌 " + key + " = " + value);
    }

    public static void file(String tag, String operation, File file) {
        String size = "";
        if (file.exists() && file.isFile()) size = ", 大小: " + formatFileSize(file.length());
        writeLog(getCurrentTime() + " [FILE  ][ " + tag + " ] 📁 " + operation + ": " + file.getAbsolutePath() + size);
    }

    public static void detail(String tag, String title, String content) {
        i(tag, "┌────────────────────────────────────────");
        i(tag, "│ " + title);
        i(tag, "├────────────────────────────────────────");
        String[] lines = content.split("\n");
        for (String line : lines) {
            i(tag, "│ " + line);
        }
        i(tag, "└────────────────────────────────────────");
    }

    public static void action(String tag, String action, String target) {
        writeLog(getCurrentTime() + " [ACTION ][ " + tag + " ] ▶ 执行 " + action + ": " + target);
    }

    public static void result(String tag, String operation, boolean success) {
        if (success) {
            writeLog(getCurrentTime() + " [RESULT ][ " + tag + " ] ✓ " + operation + " 成功");
        } else {
            writeLog(getCurrentTime() + " [RESULT ][ " + tag + " ] ✗ " + operation + " 失败");
        }
    }

    // ==================== 文件管理方法 ====================

    public static File getLogFile() { 
        return logFile; 
    }

    public static String getLogDir() { 
        return LOG_DIR; 
    }

    public static void clear(Context context) {
        try {
            if (logFile != null && logFile.exists()) {
                logFile.delete();
            }
            // 重新初始化，创建新文件
            isInitialized = false;
            init(context);
            i("LogUtils", "日志已清空");
        } catch (Exception e) { 
            e.printStackTrace(); 
        }
    }

    public static String readLog() {
        if (logFile == null || !logFile.exists()) return "";
        try {
            StringBuilder sb = new StringBuilder();
            BufferedReader reader = new BufferedReader(new FileReader(logFile));
            String line;
            while ((line = reader.readLine()) != null) {
                sb.append(line).append("\n");
            }
            reader.close();
            return sb.toString();
        } catch (Exception e) { 
            return "读取日志失败: " + e.getMessage(); 
        }
    }

    public static List<File> getAllLogFiles() {
        List<File> logFiles = new ArrayList<>();
        try {
            File logDir = new File(LOG_DIR);
            if (logDir.exists()) {
                File[] files = logDir.listFiles();
                if (files != null) {
                    for (File file : files) {
                        if (file.getName().endsWith(".log")) {
                            logFiles.add(file);
                        }
                    }
                }
            }
        } catch (Exception e) {
            e.printStackTrace();
        }
        return logFiles;
    }
}

