package com.UIN.Tool.utils;

import android.content.Context;
import android.content.SharedPreferences;

public class PreferencesUtils {
    private static final String PREF_NAME = "uin_tool_prefs";
    private static final String KEY_VIEW_MODE = "view_mode";
    private static final String KEY_WORK_FOLDER = "work_folder";
    private static final String KEY_PLUGIN_SIGNATURES = "plugin_signatures";

    private static SharedPreferences getPrefs(Context context) {
        return context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
    }

    private static SharedPreferences getSignaturePrefs(Context context) {
        return context.getSharedPreferences(KEY_PLUGIN_SIGNATURES, Context.MODE_PRIVATE);
    }

    public static void setViewMode(Context context, String mode) {
        getPrefs(context).edit().putString(KEY_VIEW_MODE, mode).apply();
    }

    public static String getViewMode(Context context) {
        return getPrefs(context).getString(KEY_VIEW_MODE, "list");
    }

    public static void setWorkFolder(Context context, String path) {
        getPrefs(context).edit().putString(KEY_WORK_FOLDER, path).apply();
    }

    public static String getWorkFolder(Context context) {
        String folder = getPrefs(context).getString(KEY_WORK_FOLDER, null);
        if (folder == null || folder.isEmpty()) {
            folder = "/storage/emulated/0/UIN_Tool";
        }
        return folder;
    }

    /**
     * 保存插件签名
     */
    public static void savePluginSignature(Context context, String pluginName, String signature) {
        getSignaturePrefs(context).edit().putString(pluginName, signature).apply();
    }

    /**
     * 获取插件签名
     */
    public static String getPluginSignature(Context context, String pluginName) {
        return getSignaturePrefs(context).getString(pluginName, null);
    }

    /**
     * 移除插件签名
     */
    public static void removePluginSignature(Context context, String pluginName) {
        getSignaturePrefs(context).edit().remove(pluginName).apply();
    }
}

package com.UIN.Tool.utils;

import android.content.Context;

import java.io.BufferedReader;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.util.HashMap;
import java.util.Map;

/**
 * 模板工具类
 * 用于加载和渲染各种模板文件
 */
public class TemplateUtils {

    private static final String TEMPLATE_BASE_PATH = "plugin_templates/";

    // Web 模板类型常量
    public static final int WEB_TEMPLATE_FULL = 0;   // 完整模板
    public static final int WEB_TEMPLATE_BLANK = 1;  // 空白模板
    public static final int WEB_TEMPLATE_SKIP = 2;   // 跳过生成

    /**
     * 加载模板文件
     * @param context 上下文
     * @param templatePath 模板路径（相对于 assets/plugin_templates/）
     * @return 模板内容字符串
     */
    public static String loadTemplate(Context context, String templatePath) throws Exception {
        InputStream is = context.getAssets().open(TEMPLATE_BASE_PATH + templatePath);
        BufferedReader reader = new BufferedReader(new InputStreamReader(is, "UTF-8"));
        StringBuilder sb = new StringBuilder();
        String line;
        while ((line = reader.readLine()) != null) {
            sb.append(line).append("\n");
        }
        reader.close();
        is.close();
        return sb.toString();
    }

    /**
     * 渲染模板，替换占位符
     * @param template 模板内容
     * @param variables 变量映射表，key 为占位符名称（不含 {{}}），value 为替换值
     * @return 渲染后的字符串
     */
    public static String renderTemplate(String template, Map<String, String> variables) {
        String result = template;
        for (Map.Entry<String, String> entry : variables.entrySet()) {
            String key = "{{" + entry.getKey() + "}}";
            String value = entry.getValue();
            if (value == null) value = "";
            result = result.replace(key, value);
        }
        return result;
    }

    /**
     * 加载并渲染模板
     * @param context 上下文
     * @param templatePath 模板路径
     * @param variables 变量映射表
     * @return 渲染后的字符串
     */
    public static String loadAndRender(Context context, String templatePath, Map<String, String> variables) throws Exception {
        String template = loadTemplate(context, templatePath);
        return renderTemplate(template, variables);
    }

    /**
     * 生成 Web 插件的所有模板文件
     * @param context 上下文
     * @param vars 变量映射表
     * @param templateType 模板类型: 0=完整模板, 1=空白模板, 2=跳过
     * @return 文件名到文件内容的映射
     */
    public static Map<String, String> generateWebTemplates(Context context, Map<String, String> vars, int templateType) throws Exception {
        Map<String, String> files = new HashMap<>();

        // 跳过模式：返回空 Map
        if (templateType == WEB_TEMPLATE_SKIP) {
            return files;
        }

        // 根据模板类型选择 index.html
        String indexTemplate;
        if (templateType == WEB_TEMPLATE_BLANK) {
            // 空白模板：使用 blank_index.html
            indexTemplate = loadAndRender(context, "web/blank_index.html", vars);
        } else {
            // 完整模板：使用 index.html
            indexTemplate = loadAndRender(context, "web/index.html", vars);
        }
        files.put("web/index.html", indexTemplate);

        // 完整模板还需要 CSS 和 JS
        if (templateType == WEB_TEMPLATE_FULL) {
            String styleCss = loadAndRender(context, "web/style.css", vars);
            String scriptJs = loadAndRender(context, "web/script.js", vars);
            files.put("web/style.css", styleCss);
            files.put("web/script.js", scriptJs);
        }

        return files;
    }

    /**
     * 生成 Java 代码
     * @param context 上下文
     * @param uiType UI类型: "native" 或 "web"
     * @param vars 变量映射表
     * @return Java 代码字符串
     */
    public static String generateJavaCode(Context context, String uiType, Map<String, String> vars) throws Exception {
        String templatePath;
        if ("web".equals(uiType)) {
            templatePath = "WebPlugin.java.tmpl";
        } else {
            templatePath = "NativePlugin.java.tmpl";
        }
        return loadAndRender(context, templatePath, vars);
    }

    /**
     * 生成 README.md 文档
     * @param context 上下文
     * @param vars 变量映射表
     * @return README 内容
     */
    public static String generateReadme(Context context, Map<String, String> vars) throws Exception {
        String template = loadTemplate(context, "README.md.tmpl");

        // 根据 UI 类型设置不同的内容
        String uiType = vars.get("UI_TYPE");
        if ("WebView".equals(uiType) || "web".equals(uiType)) {
            String webOption = vars.getOrDefault("WEB_OPTION", "完整模板");
            vars.put("WEB_SECTION", 
                "├── web/             # Web 资源目录\n" +
                "│   ├── index.html   # 主页面\n" +
                ("完整模板".equals(webOption) ? 
                "│   ├── style.css     # 样式文件\n" +
                "│   └── script.js     # JavaScript 文件\n" : 
                "│   └── (自行添加文件)\n"));
            vars.put("EXTRA_FILES", "和 `web/` 文件夹");
            vars.put("DEVELOPMENT_GUIDE", 
                "### WebView 插件开发\n\n" +
                "#### 已生成的资源\n" +
                ("完整模板".equals(webOption) ?
                "- **完整模板**：已生成 `index.html`、`style.css`、`script.js`，可直接修改\n" :
                "- **空白模板**：已生成 `index.html` 基础框架，需自行添加样式和脚本\n") +
                ("跳过生成".equals(webOption) ?
                "- **跳过模式**：`web/` 文件夹为空，需自行创建所有文件\n" : "") +
                "\n#### JavaScript API\n\n" +
                "在 HTML/JS 中可通过 `UINPlugin` 对象调用宿主功能：\n\n" +
                "```javascript\n" +
                "// 显示提示\n" +
                "UINPlugin.callHost('toast', '消息内容');\n\n" +
                "// 关闭插件\n" +
                "UINPlugin.callHost('finish', '');\n\n" +
                "// 输出日志\n" +
                "UINPlugin.callHost('log', '调试信息');\n\n" +
                "// 调用插件方法（需在 Java 端实现）\n" +
                "UINPlugin.callPlugin('methodName', JSON.stringify(params));\n" +
                "```\n\n" +
                "#### 生命周期事件\n\n" +
                "```javascript\n" +
                "window.addEventListener('resume', () => { console.log('插件恢复'); });\n" +
                "window.addEventListener('pause', () => { console.log('插件暂停'); });\n" +
                "window.addEventListener('destroy', () => { console.log('插件销毁'); });\n" +
                "```\n\n" +
                "#### 文件说明\n\n" +
                "| 文件 | 说明 |\n" +
                "|------|------|\n" +
                "| `index.html` | 主页面，必选 |\n" +
                "| `style.css` | 样式文件，可选 |\n" +
                "| `script.js` | JavaScript 逻辑，可选 |\n\n" +
                "**提示**：修改 HTML/CSS/JS 后无需重新编译，直接重新打开插件即可生效。\n");
        } else {
            vars.put("WEB_SECTION", "");
            vars.put("EXTRA_FILES", "和 `res/` 文件夹");
            vars.put("DEVELOPMENT_GUIDE",
                "### 原生插件开发\n\n" +
                "1. 编辑 `src/` 目录下的 Java 文件\n" +
                "2. 实现 `PluginInterface` 接口的所有方法\n" +
                "3. UI 必须通过 Java 代码动态创建，不能使用 XML 布局\n" +
                "4. 示例代码已自动生成，可以直接修改\n\n" +
                "#### 生命周期方法\n\n" +
                "| 方法 | 说明 |\n" +
                "|------|------|\n" +
                "| `onCreateView` | 创建插件视图，必须实现 |\n" +
                "| `onResume` | 插件恢复时调用 |\n" +
                "| `onPause` | 插件暂停时调用 |\n" +
                "| `onDestroy` | 插件销毁时调用 |\n" +
                "| `onBackPressed` | 返回键按下时调用 |\n\n" +
                "#### 注意事项\n\n" +
                "- 不要使用 Android XML 布局文件\n" +
                "- 所有 UI 控件必须通过 Java 代码动态创建\n" +
                "- 修改代码后需要重新编译生成 DEX\n");
        }

        return renderTemplate(template, vars);
    }

    /**
     * 生成默认的 plugin.json 内容
     * @param vars 变量映射表
     * @return JSON 字符串
     */
    public static String generatePluginJson(Map<String, String> vars) {
        StringBuilder json = new StringBuilder();
        json.append("{\n");
        json.append("    \"pluginId\": \"").append(escapeJson(vars.get("pluginId"))).append("\",\n");
        json.append("    \"version\": ").append(vars.getOrDefault("version", "1")).append(",\n");
        json.append("    \"versionName\": \"").append(escapeJson(vars.get("versionName"))).append("\",\n");
        json.append("    \"minHostVersion\": 1,\n");
        json.append("    \"name\": \"").append(escapeJson(vars.get("name"))).append("\",\n");
        json.append("    \"author\": \"").append(escapeJson(vars.get("author"))).append("\",\n");
        json.append("    \"description\": \"").append(escapeJson(vars.get("description"))).append("\",\n");
        json.append("    \"icon\": \"icon.png\",\n");
        json.append("    \"mainClass\": \"").append(escapeJson(vars.get("mainClass"))).append("\",\n");
        json.append("    \"apiLevel\": 21,\n");
        json.append("    \"uiType\": \"").append(escapeJson(vars.get("uiType"))).append("\",\n");
        json.append("    \"entry\": \"").append(escapeJson(vars.get("entry"))).append("\"\n");
        json.append("}");
        return json.toString();
    }

    /**
     * 转义 JSON 字符串中的特殊字符
     */
    private static String escapeJson(String str) {
        if (str == null) return "";
        return str.replace("\\", "\\\\")
                  .replace("\"", "\\\"")
                  .replace("\n", "\\n")
                  .replace("\r", "\\r")
                  .replace("\t", "\\t");
    }
}

package com.UIN.Tool.utils;

import android.content.Context;
import android.content.SharedPreferences;
import android.graphics.Color;
import android.graphics.drawable.GradientDrawable;
import android.os.Build;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;

import org.json.JSONObject;

import java.io.BufferedReader;
import java.io.File;
import java.io.FileInputStream;
import java.io.FileOutputStream;
import java.io.InputStream;
import java.io.InputStreamReader;

/**
 * UI 配置管理器
 * 支持用户自定义主题、形状、字体等
 */
public class UIConfig {

    private static UIConfig instance;
    private Context context;
    private JSONObject config;
    private String currentThemeName = "默认主题";

    private static final String CONFIG_FILE = "ui_config.json";
    private static final String PREF_NAME = "ui_prefs";
    private static final String KEY_CURRENT_THEME = "current_theme";

    private UIConfig(Context context) {
        this.context = context.getApplicationContext();
        loadConfig();
    }

    public static UIConfig getInstance(Context context) {
        if (instance == null) {
            instance = new UIConfig(context);
        }
        return instance;
    }

    /**
     * 加载配置 - 改为 public
     */
    public void loadConfig() {
        try {
            File userConfig = new File(context.getFilesDir(), CONFIG_FILE);
            if (userConfig.exists()) {
                String json = readFileToString(userConfig);
                config = new JSONObject(json);
                LogUtils.i("UIConfig", "从用户目录加载配置");
            } else {
                InputStream is = context.getAssets().open(CONFIG_FILE);
                BufferedReader reader = new BufferedReader(new InputStreamReader(is, "UTF-8"));
                StringBuilder sb = new StringBuilder();
                String line;
                while ((line = reader.readLine()) != null) {
                    sb.append(line);
                }
                reader.close();
                is.close();
                config = new JSONObject(sb.toString());
                LogUtils.i("UIConfig", "从 assets 加载默认配置");
            }

            SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
            currentThemeName = prefs.getString(KEY_CURRENT_THEME, "默认主题");

        } catch (Exception e) {
            LogUtils.e("UIConfig", "加载配置失败: " + e.getMessage());
            config = getDefaultConfig();
        }
    }

    /**
     * 保存配置
     */
    public void saveConfig() {
        try {
            File userConfig = new File(context.getFilesDir(), CONFIG_FILE);
            FileOutputStream fos = new FileOutputStream(userConfig);
            fos.write(config.toString(4).getBytes());
            fos.close();
            LogUtils.success("UIConfig", "配置已保存");
        } catch (Exception e) {
            LogUtils.e("UIConfig", "保存配置失败: " + e.getMessage());
        }
    }

    private JSONObject getDefaultConfig() {
        try {
            String json = "{\n" +
                    "  \"theme\": {\n" +
                    "    \"primaryColor\": \"#1E3A5F\",\n" +
                    "    \"primaryDarkColor\": \"#152A45\",\n" +
                    "    \"primaryLightColor\": \"#3A5A8A\",\n" +
                    "    \"accentColor\": \"#4A90E2\",\n" +
                    "    \"successColor\": \"#2ECC71\",\n" +
                    "    \"warningColor\": \"#F39C12\",\n" +
                    "    \"errorColor\": \"#E74C3C\",\n" +
                    "    \"infoColor\": \"#3498DB\",\n" +
                    "    \"backgroundColor\": \"#F0F2F5\",\n" +
                    "    \"surfaceColor\": \"#FFFFFF\",\n" +
                    "    \"textPrimaryColor\": \"#1A1A2E\",\n" +
                    "    \"textSecondaryColor\": \"#6C757D\",\n" +
                    "    \"textHintColor\": \"#ADB5BD\",\n" +
                    "    \"dividerColor\": \"#E9ECEF\"\n" +
                    "  },\n" +
                    "  \"shape\": {\n" +
                    "    \"cornerRadiusSmall\": 8,\n" +
                    "    \"cornerRadiusMedium\": 12,\n" +
                    "    \"cornerRadiusLarge\": 16,\n" +
                    "    \"cornerRadiusExtraLarge\": 24,\n" +
                    "    \"buttonCornerRadius\": 12,\n" +
                    "    \"cardCornerRadius\": 16,\n" +
                    "    \"dialogCornerRadius\": 20\n" +
                    "  }\n" +
                    "}";
            return new JSONObject(json);
        } catch (Exception e) {
            return new JSONObject();
        }
    }

    // ==================== 颜色获取方法 ====================

    public int getPrimaryColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("primaryColor", "#1E3A5F"));
    }

    public int getPrimaryDarkColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("primaryDarkColor", "#152A45"));
    }

    public int getPrimaryLightColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("primaryLightColor", "#3A5A8A"));
    }

    public int getAccentColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("accentColor", "#4A90E2"));
    }

    public int getSuccessColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("successColor", "#2ECC71"));
    }

    public int getWarningColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("warningColor", "#F39C12"));
    }

    public int getErrorColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("errorColor", "#E74C3C"));
    }

    public int getInfoColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("infoColor", "#3498DB"));
    }

    public int getBackgroundColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("backgroundColor", "#F0F2F5"));
    }

    public int getSurfaceColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("surfaceColor", "#FFFFFF"));
    }

    public int getTextPrimaryColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("textPrimaryColor", "#1A1A2E"));
    }

    public int getTextSecondaryColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("textSecondaryColor", "#6C757D"));
    }

    public int getTextHintColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("textHintColor", "#ADB5BD"));
    }

    public int getDividerColor() {
        return Color.parseColor(config.optJSONObject("theme").optString("dividerColor", "#E9ECEF"));
    }

    // ==================== 形状获取方法 ====================

    public float getCornerRadiusSmall() {
        return (float) config.optJSONObject("shape").optDouble("cornerRadiusSmall", 8);
    }

    public float getCornerRadiusMedium() {
        return (float) config.optJSONObject("shape").optDouble("cornerRadiusMedium", 12);
    }

    public float getCornerRadiusLarge() {
        return (float) config.optJSONObject("shape").optDouble("cornerRadiusLarge", 16);
    }

    public float getCornerRadiusExtraLarge() {
        return (float) config.optJSONObject("shape").optDouble("cornerRadiusExtraLarge", 24);
    }

    public float getButtonCornerRadius() {
        return (float) config.optJSONObject("shape").optDouble("buttonCornerRadius", 12);
    }

    public float getCardCornerRadius() {
        return (float) config.optJSONObject("shape").optDouble("cardCornerRadius", 16);
    }

    public float getDialogCornerRadius() {
        return (float) config.optJSONObject("shape").optDouble("dialogCornerRadius", 20);
    }

    // ==================== UI 应用方法 ====================

    public GradientDrawable createRoundedBackground(int color, float radius) {
        GradientDrawable drawable = new GradientDrawable();
        drawable.setColor(color);
        drawable.setCornerRadius(radius);
        return drawable;
    }

    public GradientDrawable createGradientBackground(int startColor, int endColor, int angle) {
        GradientDrawable drawable = new GradientDrawable();
        drawable.setColors(new int[]{startColor, endColor});
        if (angle == 0) drawable.setOrientation(GradientDrawable.Orientation.LEFT_RIGHT);
        else if (angle == 90) drawable.setOrientation(GradientDrawable.Orientation.BOTTOM_TOP);
        else if (angle == 180) drawable.setOrientation(GradientDrawable.Orientation.RIGHT_LEFT);
        else if (angle == 270) drawable.setOrientation(GradientDrawable.Orientation.TOP_BOTTOM);
        else drawable.setOrientation(GradientDrawable.Orientation.TL_BR);
        return drawable;
    }

    public void applyTheme(android.app.Activity activity) {
        if (activity == null) return;

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
            activity.getWindow().setStatusBarColor(getPrimaryDarkColor());
            activity.getWindow().setNavigationBarColor(getSurfaceColor());
        }

        View root = activity.getWindow().getDecorView().findViewById(android.R.id.content);
        if (root != null) {
            root.setBackgroundColor(getBackgroundColor());
        }
    }

    public void applyThemeToView(View view) {
        if (view == null) return;

        if (view instanceof TextView) {
            TextView tv = (TextView) view;
            tv.setTextColor(getTextPrimaryColor());
        }

        if (view instanceof Button) {
            Button btn = (Button) view;
            GradientDrawable drawable = createRoundedBackground(getPrimaryColor(), getButtonCornerRadius());
            btn.setBackground(drawable);
            btn.setTextColor(Color.WHITE);
        }
    }

    private String readFileToString(File file) {
        try {
            FileInputStream fis = new FileInputStream(file);
            byte[] data = new byte[(int) file.length()];
            fis.read(data);
            fis.close();
            return new String(data, "UTF-8");
        } catch (Exception e) {
            return null;
        }
    }

    public void exportConfig(File destFile) throws Exception {
        FileOutputStream fos = new FileOutputStream(destFile);
        fos.write(config.toString(4).getBytes());
        fos.close();
    }

    public boolean importConfig(File sourceFile) {
        try {
            String json = readFileToString(sourceFile);
            config = new JSONObject(json);
            saveConfig();
            return true;
        } catch (Exception e) {
            LogUtils.e("UIConfig", "导入配置失败: " + e.getMessage());
            return false;
        }
    }

    public void resetToDefault() {
        config = getDefaultConfig();
        saveConfig();
    }

    public void updateColor(String key, String colorValue) {
        try {
            config.getJSONObject("theme").put(key, colorValue);
            saveConfig();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    public JSONObject getConfig() {
        return config;
    }

    public String getCurrentThemeName() {
        return currentThemeName;
    }

    public void setCurrentThemeName(String name) {
        this.currentThemeName = name;
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        prefs.edit().putString(KEY_CURRENT_THEME, name).apply();
    }
}

package com.UIN.Tool.widget;

import android.content.Context;
import android.content.SharedPreferences;

import androidx.annotation.Nullable;

/**
 * 1x1 小部件配置存储。
 * 每个小部件实例可绑定一个插件 ID，点击时直接启动该插件。
 */
public class Widget1x1Config {

    private static final String PREF_NAME = "uin_widget_1x1_prefs";

    public String pluginId;

    public Widget1x1Config() {
        this.pluginId = "";
    }

    public Widget1x1Config(String pluginId) {
        this.pluginId = pluginId != null ? pluginId : "";
    }

    public boolean hasPlugin() {
        return !pluginId.isEmpty();
    }

    public void save(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        prefs.edit()
                .putString("widget_1x1_" + appWidgetId + "_plugin", pluginId)
                .apply();
    }

    @Nullable
    public static Widget1x1Config load(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        String id = prefs.getString("widget_1x1_" + appWidgetId + "_plugin", "");
        if (id.isEmpty()) {
            return null;
        }
        return new Widget1x1Config(id);
    }

    public static void delete(Context context, int appWidgetId) {
        SharedPreferences prefs = context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE);
        prefs.edit()
                .remove("widget_1x1_" + appWidgetId + "_plugin")
                .apply();
    }
}

package com.UIN.Tool.widget;

import android.app.PendingIntent;
import android.appwidget.AppWidgetManager;
import android.appwidget.AppWidgetProvider;
import android.content.ComponentName;
import android.content.Context;
import android.content.Intent;
import android.graphics.Bitmap;
import android.graphics.BitmapFactory;
import android.net.Uri;
import android.os.Build;
import android.widget.RemoteViews;

import androidx.annotation.NonNull;

import com.UIN.Tool.MainActivity;
import com.UIN.Tool.R;
import com.UIN.Tool.plugin.PluginHostActivity;
import com.UIN.Tool.plugin.PluginInfo;
import com.UIN.Tool.plugin.PluginManager;
import com.UIN.Tool.utils.LogUtils;

import java.io.File;

/**
 * 1x1 桌面小部件提供者。
 * 可绑定一个特定插件作为快捷方式，点击直接启动该插件；
 * 未选择插件时，点击打开 UIN Tool 主界面。
 */
public class Widget1x1Provider extends AppWidgetProvider {

    private static final String TAG = "Widget1x1Provider";

    public static final String ACTION_REFRESH_WIDGET_1x1 = "com.UIN.Tool.REFRESH_WIDGET_1x1";

    @Override
    public void onEnabled(Context context) {
        super.onEnabled(context);
        LogUtils.i(TAG, "1x1 Widget provider enabled");
    }

    @Override
    public void onUpdate(Context context, AppWidgetManager appWidgetManager, int[] appWidgetIds) {
        super.onUpdate(context, appWidgetManager, appWidgetIds);

        LogUtils.i(TAG, "onUpdate: " + (appWidgetIds != null ? appWidgetIds.length : 0) + " widgets");

        if (appWidgetIds == null || appWidgetIds.length == 0) {
            return;
        }

        for (int appWidgetId : appWidgetIds) {
            updateAppWidget(context, appWidgetManager, appWidgetId);
        }
    }

    public static void updateAppWidget(@NonNull Context context,
                                        @NonNull AppWidgetManager appWidgetManager,
                                        int appWidgetId) {
        if (appWidgetId == AppWidgetManager.INVALID_APPWIDGET_ID) {
            LogUtils.e(TAG, "updateAppWidget: Invalid appWidgetId");
            return;
        }

        LogUtils.d(TAG, "updateAppWidget: Updating 1x1 widget " + appWidgetId);

        RemoteViews views = new RemoteViews(context.getPackageName(), R.layout.widget_layout_1x1);

        // 读取配置，检查是否绑定了插件
        Widget1x1Config config = Widget1x1Config.load(context, appWidgetId);
        boolean hasPlugin = config != null && config.hasPlugin();

        if (hasPlugin) {
            // 绑定了特定插件 → 显示插件图标和名称，点击启动该插件
            PluginManager pm = PluginManager.getInstance(context);
            PluginInfo info = pm.getPluginInfo(config.pluginId);

            if (info != null) {
                views.setTextViewText(R.id.widget_1x1_label, info.name);
                Bitmap icon = loadPluginIcon(context, pm, info);
                if (icon != null) {
                    views.setImageViewBitmap(R.id.widget_1x1_icon, icon);
                } else {
                    views.setImageViewResource(R.id.widget_1x1_icon, R.drawable.ic_extension);
                }

                // 点击 → 直接启动该插件
                Intent pluginIntent = new Intent(context, PluginHostActivity.class);
                pluginIntent.putExtra(PluginHostActivity.EXTRA_PLUGIN_ID, info.pluginId);
                pluginIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK);
                pluginIntent.setData(Uri.parse("widget1x1://plugin/" + appWidgetId));

                PendingIntent pendingIntent = PendingIntent.getActivity(context,
                        appWidgetId, pluginIntent, getPendingIntentFlags());
                views.setOnClickPendingIntent(R.id.widget_1x1_root, pendingIntent);

                LogUtils.i(TAG, "Widget " + appWidgetId + " bound to plugin: " + info.name);
            } else {
                // 插件已被卸载 → 回退到主界面
                LogUtils.w(TAG, "Widget " + appWidgetId + " plugin not found: " + config.pluginId);
                setupMainAppShortcut(context, views, appWidgetId);
            }
        } else {
            // 未绑定插件 → 显示应用图标和名称，点击打开主界面
            setupMainAppShortcut(context, views, appWidgetId);
        }

        appWidgetManager.updateAppWidget(appWidgetId, views);
        LogUtils.success(TAG, "1x1 Widget " + appWidgetId + " updated successfully");
    }

    /**
     * 设置为打开主界面的快捷方式（默认行为）。
     */
    private static void setupMainAppShortcut(@NonNull Context context,
                                              @NonNull RemoteViews views,
                                              int appWidgetId) {
        views.setTextViewText(R.id.widget_1x1_label, context.getString(R.string.app_name));
        views.setImageViewResource(R.id.widget_1x1_icon, R.drawable.ic_launcher_foreground);

        Intent openIntent = new Intent(context, MainActivity.class);
        openIntent.addFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TOP);
        openIntent.setData(Uri.parse("widget1x1://open/" + appWidgetId));

        PendingIntent pendingIntent = PendingIntent.getActivity(context,
                appWidgetId, openIntent, getPendingIntentFlags());
        views.setOnClickPendingIntent(R.id.widget_1x1_root, pendingIntent);
    }

    /**
     * 加载插件图标，缩放到小部件尺寸。
     */
    private static Bitmap loadPluginIcon(Context context, PluginManager pm, PluginInfo plugin) {
        try {
            File pluginDir = pm.getPluginDirFile(plugin.pluginId);
            if (pluginDir != null && pluginDir.exists()) {
                String iconPath = plugin.icon != null && !plugin.icon.isEmpty()
                        ? plugin.icon : "icon.png";
                File iconFile = new File(pluginDir, iconPath);
                if (iconFile.exists()) {
                    BitmapFactory.Options options = new BitmapFactory.Options();
                    options.inSampleSize = 2;
                    Bitmap bitmap = BitmapFactory.decodeFile(iconFile.getAbsolutePath(), options);
                    if (bitmap != null) {
                        return Bitmap.createScaledBitmap(bitmap, 48, 48, true);
                    }
                }
            }
        } catch (Exception e) {
            LogUtils.e(TAG, "Failed to load plugin icon: " + e.getMessage());
        }
        return null;
    }

    @Override
    public void onReceive(Context context, Intent intent) {
        String action = intent != null ? intent.getAction() : null;

        LogUtils.d(TAG, "onReceive called with action: " + action);

        if (action == null) {
            super.onReceive(context, intent);
            return;
        }

        if (ACTION_REFRESH_WIDGET_1x1.equals(action)) {
            int appWidgetId = intent.getIntExtra(AppWidgetManager.EXTRA_APPWIDGET_ID,
                    AppWidgetManager.INVALID_APPWIDGET_ID);
            LogUtils.d(TAG, "Refresh 1x1 widget: " + appWidgetId);

            if (appWidgetId != AppWidgetManager.INVALID_APPWIDGET_ID) {
                refreshSingleWidget(context, appWidgetId);
            } else {
                refreshAllWidgets(context);
            }
        } else {
            super.onReceive(context, intent);
        }
    }

    public static void refreshAllWidgets(Context context) {
        LogUtils.i(TAG, "refreshAllWidgets called");

        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(context);
        ComponentName componentName = new ComponentName(context, Widget1x1Provider.class);
        int[] appWidgetIds = appWidgetManager.getAppWidgetIds(componentName);

        if (appWidgetIds != null && appWidgetIds.length > 0) {
            for (int appWidgetId : appWidgetIds) {
                refreshSingleWidget(context, appWidgetId);
            }
        }
    }

    public static void refreshSingleWidget(Context context, int appWidgetId) {
        LogUtils.d(TAG, "refreshSingleWidget called for 1x1 widget " + appWidgetId);

        AppWidgetManager appWidgetManager = AppWidgetManager.getInstance(context);
        updateAppWidget(context, appWidgetManager, appWidgetId);
    }

    public static void sendRefreshIntent(Context context) {
        LogUtils.i(TAG, "sendRefreshIntent called");

        Intent intent = new Intent(ACTION_REFRESH_WIDGET_1x1);
        intent.setClass(context, Widget1x1Provider.class);
        intent.putExtra(AppWidgetManager.EXTRA_APPWIDGET_ID, AppWidgetManager.INVALID_APPWIDGET_ID);
        context.sendBroadcast(intent);
    }

    private static int getPendingIntentFlags() {
        int flags = PendingIntent.FLAG_UPDATE_CURRENT;
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            flags |= PendingIntent.FLAG_IMMUTABLE;
        }
        return flags;
    }

    @Override
    public void onDeleted(Context context, int[] appWidgetIds) {
        super.onDeleted(context, appWidgetIds);
        if (appWidgetIds != null) {
            for (int appWidgetId : appWidgetIds) {
                Widget1x1Config.delete(context, appWidgetId);
            }
            LogUtils.i(TAG, "1x1 Widgets deleted: " + appWidgetIds.length);
        }
    }

    @Override
    public void onDisabled(Context context) {
        super.onDisabled(context);
        LogUtils.i(TAG, "1x1 Widget provider disabled");
    }
}
